def rect(kind: str, x: float, y: float, width: float, height: float) -> dict[str, Any]:
    obj = {
        "id": object_id(),
        "type": kind,
        "x": x,
        "y": y,
        "width": width,
        "height": height,
    }
    if kind in {"room", "round", "cave"}:
        obj.update(campaign_room_fields())
    if kind == "cave_corridor":
        obj["seed"] = random.randint(1, 100000)
        obj["wallType"] = "natural"
        obj["wallThickness"] = 0.22
    return obj


def cave_corridor_from_points(
    points: list[tuple[float, float]], smooth_boundary: bool = True
) -> dict[str, Any]:
    point_dicts = [{"x": x, "y": y} for x, y in points]
    x, y, width, height = bounds_from_points(point_dicts)
    return {
        "id": object_id(),
        "type": "cave_corridor",
        "x": x,
        "y": y,
        "width": width,
        "height": height,
        "points": point_dicts,
        "seed": random.randint(1, 100000),
        "wallType": "natural",
        "wallThickness": 0.22,
        "smoothBoundary": bool(smooth_boundary),
        "layer": "corridors",
    }


def polygon_room_from_points(points: list[tuple[float, float]]) -> dict[str, Any]:
    point_dicts = [{"x": x, "y": y} for x, y in points]
    x, y, width, height = bounds_from_points(point_dicts)
    obj = {
        "id": object_id(),
        "type": "room",
        "x": x,
        "y": y,
        "width": width,
        "height": height,
        "points": point_dicts,
        "wallType": "standard",
        "wallThickness": 0.16,
        "layer": "rooms",
    }
    obj.update(campaign_room_fields())
    return obj


