def shape(
    kind: str,
    x: float,
    y: float,
    width: float,
    height: float,
    x2: float | None = None,
    y2: float | None = None,
) -> dict[str, Any]:
    obj = {
        "id": object_id(),
        "type": "shape",
        "kind": kind,
        "x": x,
        "y": y,
        "lineWidth": 0.12,
        "strokeColor": "",
        "fillColor": "",
        "opacity": 1.0,
        "lineStyle": "solid",
        "curve": False,
        "arrow": "none",
        "rotation": 0.0,
        "layer": "shapes",
    }
    if kind == "line":
        obj["x2"] = x2 if x2 is not None else x + width
        obj["y2"] = y2 if y2 is not None else y + height
    else:
        obj["width"] = width
        obj["height"] = height
        if kind == "polygon":
            obj["points"] = [
                {"x": px, "y": py}
                for px, py in regular_polygon_points(x, y, width, height, 6)
            ]
    return obj


