class ToolTip:
    active_instances = weakref.WeakSet["ToolTip"]()

    def __init__(
        self,
        widget: tk.Widget,
        text: str,
        enabled: Callable[[], bool] | None = None,
    ) -> None:
        self.widget = widget
        self.text = text
        self.tip: tk.Toplevel | None = None
        self.enabled = enabled or (lambda: True)
        self.active_instances.add(self)
        widget.bind("<Enter>", self.show, add="+")
        widget.bind("<Leave>", self.hide, add="+")
        widget.bind("<ButtonPress>", self.hide, add="+")

    def show(self, _event: tk.Event | None = None) -> None:
        if self.tip or not self.text or not self.enabled():
            return
        self.tip = tk.Toplevel(self.widget)
        self.tip.wm_overrideredirect(True)
        label = tk.Label(
            self.tip,
            text=self.text,
            background="#17384a",
            foreground="#ffffff",
            borderwidth=0,
            padx=8,
            pady=4,
            font=("Segoe UI", 9),
            justify="left",
            wraplength=280,
        )
        label.pack()
        self.tip.update_idletasks()
        tip_width = self.tip.winfo_reqwidth()
        tip_height = self.tip.winfo_reqheight()
        screen_width = self.widget.winfo_screenwidth()
        screen_height = self.widget.winfo_screenheight()
        right_x = self.widget.winfo_rootx() + self.widget.winfo_width() + 8
        left_x = self.widget.winfo_rootx() - tip_width - 8
        x = left_x if right_x + tip_width > screen_width else right_x
        x = max(0, min(x, screen_width - tip_width))
        y = max(0, min(self.widget.winfo_rooty() + 4, screen_height - tip_height))
        self.tip.wm_geometry(f"+{x}+{y}")

    def hide(self, _event: tk.Event | None = None) -> None:
        if self.tip:
            self.tip.destroy()
            self.tip = None

    @classmethod
    def hide_all(cls) -> None:
        for tooltip in list(cls.active_instances):
            tooltip.hide()


class SymbolPreview:
    active_instances = weakref.WeakSet["SymbolPreview"]()

    def __init__(
        self, widget: tk.Widget, app: "OSRMapMaker", kind: str, label: str
    ) -> None:
        self.widget = widget
        self.app = app
        self.kind = kind
        self.label = label
        self.tip: tk.Toplevel | None = None
        self.active_instances.add(self)
        widget.bind("<Enter>", self.show, add="+")
        widget.bind("<Leave>", self.hide, add="+")
        widget.bind("<ButtonPress>", self.hide, add="+")

    def show(self, _event: tk.Event | None = None) -> None:
        if self.tip or not self.app.tooltips_enabled():
            return
        self.tip = tk.Toplevel(self.widget)
        self.tip.wm_overrideredirect(True)
        canvas = tk.Canvas(
            self.tip,
            width=190,
            height=158,
            bg="#f9fcfd",
            highlightthickness=1,
            highlightbackground="#9bb8c4",
        )
        canvas.pack()
        draw_symbol_preview_canvas(canvas, self.app.project, self.kind, self.label)
        tags = ", ".join(symbol_tags(self.app.project, self.kind)[:6]) or "no tags"
        variants = symbol_variant_options(self.app.project, self.kind)
        size = self.app.settings.get(
            "defaultSymbolSizePreset", DEFAULT_SYMBOL_SIZE_PRESET
        )
        canvas.create_text(
            96, 108, text=self.label[:28], fill="#17384a", font=("Segoe UI", 9, "bold")
        )
        canvas.create_text(
            96,
            126,
            text=f"{len(variants)} variant(s) | {size}",
            fill="#365b68",
            font=("Segoe UI", 8),
        )
        canvas.create_text(
            96, 144, text=tags[:42], fill="#365b68", font=("Segoe UI", 8)
        )
        self.tip.update_idletasks()
        tip_width = self.tip.winfo_reqwidth()
        tip_height = self.tip.winfo_reqheight()
        screen_width = self.widget.winfo_screenwidth()
        screen_height = self.widget.winfo_screenheight()
        right_x = self.widget.winfo_rootx() + self.widget.winfo_width() + 8
        left_x = self.widget.winfo_rootx() - tip_width - 8
        x = left_x if right_x + tip_width > screen_width else right_x
        x = max(0, min(x, screen_width - tip_width))
        y = max(0, min(self.widget.winfo_rooty() + 34, screen_height - tip_height))
        self.tip.wm_geometry(f"+{x}+{y}")

    def hide(self, _event: tk.Event | None = None) -> None:
        if self.tip:
            self.tip.destroy()
            self.tip = None

    @classmethod
    def hide_all(cls) -> None:
        for preview in list(cls.active_instances):
            preview.hide()


