def svg_vector_symbol_parts(
    kind: str, x: float, y: float, s: float, ink: str, floor: str, width: int
) -> list[str]:
    parts: list[str] = []
    for op in vector_symbol_ops(kind):
        op_type = op[0]
        if op_type == "line":
            x1, y1, x2, y2 = (x + op[1] * s, y + op[2] * s, x + op[3] * s, y + op[4] * s)
            parts.append(
                f'<line x1="{x1:.2f}" y1="{y1:.2f}" x2="{x2:.2f}" y2="{y2:.2f}" stroke="{ink}" stroke-width="{width}" stroke-linecap="round" stroke-linejoin="round"/>'
            )
        elif op_type == "polyline":
            points = vector_symbol_points(x, y, s, op[1])
            parts.append(
                f'<polyline points="{svg_points(points)}" fill="none" stroke="{ink}" stroke-width="{width}" stroke-linecap="round" stroke-linejoin="round"/>'
            )
        elif op_type == "polygon":
            points = vector_symbol_points(x, y, s, op[1])
            fill = vector_symbol_fill(op[2], ink, floor)
            parts.append(
                f'<polygon points="{svg_points(points)}" fill="{fill or "none"}" stroke="{ink}" stroke-width="{width}" stroke-linejoin="round"/>'
            )
        elif op_type == "rect":
            left, top, right, bottom = (
                x + op[1] * s,
                y + op[2] * s,
                x + op[3] * s,
                y + op[4] * s,
            )
            fill = vector_symbol_fill(op[5], ink, floor)
            parts.append(
                f'<rect x="{left:.2f}" y="{top:.2f}" width="{right - left:.2f}" height="{bottom - top:.2f}" fill="{fill or "none"}" stroke="{ink}" stroke-width="{width}"/>'
            )
        elif op_type == "ellipse":
            fill = vector_symbol_fill(op[5], ink, floor)
            parts.append(
                f'<ellipse cx="{x + op[1] * s:.2f}" cy="{y + op[2] * s:.2f}" rx="{op[3] * s:.2f}" ry="{op[4] * s:.2f}" fill="{fill or "none"}" stroke="{ink}" stroke-width="{width}"/>'
            )
        elif op_type == "text":
            value, tx, ty, factor = op[1], x + op[2] * s, y + op[3] * s, op[4]
            parts.append(
                f'<text x="{tx:.2f}" y="{ty:.2f}" fill="{ink}" font-size="{max(7, int(s * factor))}" font-family="Arial" font-weight="bold" text-anchor="middle" dominant-baseline="middle">{escape_xml(value)}</text>'
            )
    return parts


def svg_for_symbol(
    kind: str,
    x: float,
    y: float,
    s: float,
    ink: str,
    floor: str,
    scale: int,
    rotation: float = 0.0,
    fallback_label: str = "",
) -> list[str]:
    kind = normalize_symbol_kind(kind)
    width = max(1, scale * 2)
    parts: list[str] = []

    def line(x1: float, y1: float, x2: float, y2: float) -> None:
        parts.append(
            f'<line x1="{x1:.2f}" y1="{y1:.2f}" x2="{x2:.2f}" y2="{y2:.2f}" stroke="{ink}" stroke-width="{width}" stroke-linecap="round" stroke-linejoin="round"/>'
        )

    def polyline(points: list[tuple[float, float]], fill: str = "none") -> None:
        parts.append(
            f'<polyline points="{svg_points(points)}" fill="{fill}" stroke="{ink}" stroke-width="{width}" stroke-linecap="round" stroke-linejoin="round"/>'
        )

    def polygon(points: list[tuple[float, float]], fill: str = ink) -> None:
        parts.append(
            f'<polygon points="{svg_points(points)}" fill="{fill}" stroke="{ink}" stroke-width="{max(1, width)}" stroke-linejoin="round"/>'
        )

    def rect(
        left: float,
        top: float,
        right: float,
        bottom: float,
        fill: str = "none",
        stroke: str = ink,
    ) -> None:
        parts.append(
            f'<rect x="{left:.2f}" y="{top:.2f}" width="{right - left:.2f}" height="{bottom - top:.2f}" fill="{fill}" stroke="{stroke}" stroke-width="{width}"/>'
        )

    def ellipse(cx: float, cy: float, rx: float, ry: float, fill: str = "none") -> None:
        parts.append(
            f'<ellipse cx="{cx:.2f}" cy="{cy:.2f}" rx="{rx:.2f}" ry="{ry:.2f}" fill="{fill}" stroke="{ink}" stroke-width="{width}"/>'
        )

    def text(value: str, tx: float = x, ty: float = y, factor: float = 0.65) -> None:
        parts.append(
            f'<text x="{tx:.2f}" y="{ty:.2f}" fill="{ink}" font-size="{max(7, int(s * factor))}" font-family="Arial" font-weight="bold" text-anchor="middle" dominant-baseline="middle">{escape_xml(value)}</text>'
        )

    if kind in DOOR_SYMBOLS:
        rect(x - s * 0.48, y - s * 0.2, x + s * 0.48, y + s * 0.2, floor)
        line(x - s * 0.48, y, x + s * 0.48, y)
        if kind == "door":
            rect(x - s * 0.16, y - s * 0.09, x + s * 0.16, y + s * 0.09, floor)
        elif kind == "double_door":
            rect(x - s * 0.34, y - s * 0.09, x - s * 0.05, y + s * 0.09, floor)
            rect(x + s * 0.05, y - s * 0.09, x + s * 0.34, y + s * 0.09, floor)
        elif kind in {"secret_door", "concealed_door"}:
            text("S" if kind == "secret_door" else "C", factor=0.55)
        elif kind == "one_way_door":
            polygon(
                [
                    (x - s * 0.12, y - s * 0.02),
                    (x + s * 0.12, y - s * 0.02),
                    (x, y + s * 0.18),
                ]
            )
        elif kind == "false_door":
            parts.append(
                f'<path d="M {x - s * 0.22:.2f} {y + s * 0.18:.2f} Q {x:.2f} {y - s * 0.08:.2f} {x + s * 0.22:.2f} {y + s * 0.18:.2f}" fill="none" stroke="{ink}" stroke-width="{width}" stroke-linecap="round"/>'
            )
        elif kind == "locked_door":
            rect(x - s * 0.13, y - s * 0.1, x + s * 0.13, y + s * 0.1)
            ellipse(x, y, s * 0.04, s * 0.04, ink)
        elif kind in {"archway", "archway_door"}:
            line(x - s * 0.2, y - s * 0.12, x + s * 0.2, y - s * 0.12)
            line(x, y - s * 0.12, x, y + s * 0.16)
        elif kind == "barred_door":
            for offset in (-0.16, 0, 0.16):
                rect(
                    x + s * offset - s * 0.04,
                    y - s * 0.12,
                    x + s * offset + s * 0.04,
                    y + s * 0.12,
                    ink,
                )
        elif kind == "portcullis":
            for offset in (-0.18, 0, 0.18):
                ellipse(x + s * offset, y, s * 0.035, s * 0.035, ink)
        elif kind == "one_way_secret_door":
            text("S", x - s * 0.12, y, 0.45)
            polygon(
                [
                    (x + s * 0.02, y - s * 0.04),
                    (x + s * 0.22, y - s * 0.04),
                    (x + s * 0.12, y + s * 0.14),
                ]
            )
        elif kind == "window":
            rect(x - s * 0.25, y - s * 0.05, x + s * 0.25, y + s * 0.05, ink)
        elif kind == "arrow_slit":
            polygon(
                [
                    (x - s * 0.25, y - s * 0.1),
                    (x - s * 0.05, y + s * 0.1),
                    (x - s * 0.28, y + s * 0.1),
                ]
            )
            polygon(
                [
                    (x + s * 0.25, y - s * 0.1),
                    (x + s * 0.05, y + s * 0.1),
                    (x + s * 0.28, y + s * 0.1),
                ]
            )
        elif kind == "open_door":
            line(x - s * 0.05, y, x + s * 0.25, y - s * 0.28)
        elif kind == "revolving_door":
            parts.append(
                f'<path d="M {x + s * 0.22:.2f} {y:.2f} A {s * 0.24:.2f} {s * 0.24:.2f} 0 1 1 {x + s * 0.18:.2f} {y - s * 0.16:.2f}" fill="none" stroke="{ink}" stroke-width="{width}"/>'
            )
            line(x, y, x + s * 0.22, y)
        else:
            text(symbol_icon(kind).strip()[:2], factor=0.52)
    elif kind in HAZARD_SYMBOLS:
        rect(x - s * 0.45, y - s * 0.45, x + s * 0.45, y + s * 0.45)
        if kind == "covered_pit":
            line(x - s * 0.32, y - s * 0.32, x + s * 0.32, y + s * 0.32)
            line(x + s * 0.32, y - s * 0.32, x - s * 0.32, y + s * 0.32)
        elif kind == "open_pit":
            rect(x - s * 0.25, y - s * 0.25, x + s * 0.25, y + s * 0.25, ink)
        else:
            text(
                {
                    "trap": "T",
                    "trap_ceiling": "C",
                    "trap_floor": "F",
                    "secret_trap_door": "S",
                }.get(kind, symbol_icon(kind).strip()[:2]),
                factor=0.72,
            )
    elif kind in {"stairs", "stair_slide_trap", "natural_stairs"}:
        for index in range(7):
            line(
                x - s * 0.55 + index * s * 0.16,
                y - s * 0.45,
                x - s * 0.3 + index * s * 0.16,
                y + s * 0.45,
            )
        if kind == "stair_slide_trap":
            line(x - s * 0.48, y + s * 0.45, x + s * 0.48, y + s * 0.45)
        if kind == "natural_stairs":
            parts.append(
                f'<path d="M {x - s * 0.5:.2f} {y:.2f} Q {x:.2f} {y - s * 0.45:.2f} {x + s * 0.5:.2f} {y:.2f}" fill="none" stroke="{ink}" stroke-width="{width}"/>'
            )
    elif kind == "spiral_stairs":
        for radius in (0.15, 0.3, 0.45):
            ellipse(x, y, s * radius, s * radius)
        line(x, y, x + s * 0.45, y)
    elif kind == "ladder":
        line(x - s * 0.25, y - s * 0.45, x - s * 0.25, y + s * 0.45)
        line(x + s * 0.25, y - s * 0.45, x + s * 0.25, y + s * 0.45)
        for index in range(5):
            yy = y - s * 0.35 + index * s * 0.18
            line(x - s * 0.25, yy, x + s * 0.25, yy)
    elif kind == "slide":
        line(x - s * 0.45, y, x + s * 0.35, y)
        line(x + s * 0.18, y - s * 0.18, x + s * 0.38, y)
        line(x + s * 0.18, y + s * 0.18, x + s * 0.38, y)
    elif kind in {"pillar", "rock_column", "boulder", "boulder_cluster"}:
        if kind == "boulder_cluster":
            for ox, oy, radius in ((-0.18, 0.08, 0.22), (0.14, -0.1, 0.26), (0.28, 0.2, 0.16)):
                ellipse(x + s * ox, y + s * oy, s * radius, s * radius, ink)
        else:
            ellipse(x, y, s * (0.36 if kind == "boulder" else 0.3), s * (0.28 if kind == "boulder" else 0.3), ink)
        if kind == "rock_column":
            text("x", factor=0.6)
    elif kind == "statue":
        ellipse(x, y, s * 0.45, s * 0.45)
        text("*", factor=1.0)
    elif kind in {"fountain", "well"}:
        ellipse(x, y, s * 0.42, s * 0.42)
        ellipse(x, y, s * 0.18, s * 0.18)
    elif kind in {"pool", "pool_lake", "stream", "curtain", "submerged_path"}:
        for index in range(3):
            yy = y - s * 0.25 + index * s * 0.25
            polyline(
                [
                    (x - s * 0.42, yy),
                    (x - s * 0.15, yy + s * 0.08),
                    (x + s * 0.15, yy - s * 0.08),
                    (x + s * 0.42, yy),
                ]
            )
    elif kind in {"dais", "teleporter"}:
        rect(x - s * 0.42, y - s * 0.42, x + s * 0.42, y + s * 0.42)
        rect(x - s * 0.25, y - s * 0.25, x + s * 0.25, y + s * 0.25)
        if kind == "teleporter":
            for index in range(9):
                px = x - s * 0.25 + (index % 3) * s * 0.25
                py = y - s * 0.25 + (index // 3) * s * 0.25
                rect(px, py, px + s * 0.08, py + s * 0.08, ink)
    elif kind == "altar":
        rect(x - s * 0.2, y - s * 0.48, x + s * 0.2, y + s * 0.48)
        rect(x - s * 0.07, y - s * 0.22, x + s * 0.07, y - s * 0.08, ink)
        rect(x - s * 0.07, y + s * 0.12, x + s * 0.07, y + s * 0.26, ink)
    elif kind == "fireplace":
        rect(x - s * 0.38, y - s * 0.4, x + s * 0.38, y + s * 0.15)
        parts.append(
            f'<path d="M {x - s * 0.25:.2f} {y + s * 0.2:.2f} Q {x:.2f} {y - s * 0.1:.2f} {x + s * 0.25:.2f} {y + s * 0.2:.2f}" fill="none" stroke="{ink}" stroke-width="{width}"/>'
        )
    elif kind == "table_chest":
        rect(x - s * 0.45, y - s * 0.2, x - s * 0.05, y + s * 0.2)
        rect(x + s * 0.08, y - s * 0.18, x + s * 0.42, y + s * 0.18)
        line(x + s * 0.08, y, x + s * 0.42, y)
    elif kind == "bed":
        rect(x - s * 0.42, y - s * 0.25, x + s * 0.42, y + s * 0.25)
        line(x - s * 0.18, y - s * 0.25, x - s * 0.18, y + s * 0.25)
    elif kind in {"railing", "illusory_wall", "rock_wall", "subterranean_passage"}:
        if kind == "railing":
            for index in range(5):
                ellipse(x - s * 0.41 + index * s * 0.22, y, s * 0.04, s * 0.06, ink)
        elif kind == "illusory_wall":
            for index in range(4):
                line(
                    x - s * 0.45 + index * s * 0.24,
                    y,
                    x - s * 0.32 + index * s * 0.24,
                    y,
                )
        elif kind == "subterranean_passage":
            rect(x - s * 0.45, y - s * 0.28, x + s * 0.45, y + s * 0.28, ink)
        else:
            for index in range(5):
                yy = y - s * 0.3 + index * s * 0.15
                line(x - s * 0.45, yy, x + s * 0.45, yy)
    elif kind in {"stalactite", "stalagmite"}:
        points = (
            [
                (x - s * 0.35, y - s * 0.35),
                (x + s * 0.35, y - s * 0.35),
                (x, y + s * 0.35),
            ]
            if kind == "stalactite"
            else [
                (x - s * 0.35, y + s * 0.35),
                (x + s * 0.35, y + s * 0.35),
                (x, y - s * 0.35),
            ]
        )
        polygon(points, floor)
    elif kind in {"rubble", "rubble_pile", "debris_field", "rockfall", "cave_in", "depression"}:
        if kind == "cave_in":
            rect(x - s * 0.42, y - s * 0.26, x + s * 0.42, y + s * 0.26)
            line(x - s * 0.34, y - s * 0.18, x + s * 0.34, y + s * 0.18)
            line(x + s * 0.34, y - s * 0.18, x - s * 0.34, y + s * 0.18)
        count = 14 if kind in {"rubble_pile", "rockfall", "cave_in"} else 9
        for index in range(count):
            angle = index * math.tau / 9
            radius = s * (0.12 + 0.34 * ((index % 4) / 3))
            ellipse(
                x + math.cos(angle) * radius,
                y + math.sin(angle) * radius,
                s * (0.04 + 0.02 * (index % 2)),
                s * (0.04 + 0.02 * (index % 2)),
                ink if kind != "depression" else floor,
            )
    elif kind in {"crevasse", "cracked_ground", "sinkhole", "elevated_ledge", "natural_chimney"}:
        if kind == "sinkhole":
            for radius in (0.42, 0.27, 0.12):
                ellipse(x, y, s * radius, s * radius)
        elif kind == "natural_chimney":
            for index in range(8):
                angle = index * math.tau / 8
                line(
                    x, y, x + math.cos(angle) * s * 0.42, y + math.sin(angle) * s * 0.42
                )
        elif kind == "elevated_ledge":
            polyline(
                [
                    (x - s * 0.45, y - s * 0.1),
                    (x - s * 0.2, y + s * 0.25),
                    (x + s * 0.1, y + s * 0.1),
                    (x + s * 0.45, y + s * 0.3),
                ]
            )
            line(x - s * 0.45, y - s * 0.25, x + s * 0.45, y - s * 0.05)
        elif kind in {"crevasse", "cracked_ground"}:
            polyline(
                [
                    (x - s * 0.4, y - s * 0.4),
                    (x - s * 0.1, y - s * 0.1),
                    (x - s * 0.25, y + s * 0.2),
                    (x + s * 0.15, y),
                    (x + s * 0.4, y + s * 0.35),
                ]
            )
            if kind == "cracked_ground":
                line(x - s * 0.05, y - s * 0.08, x - s * 0.28, y + s * 0.22)
                line(x + s * 0.08, y, x + s * 0.32, y - s * 0.24)
    else:
        vector_parts = svg_vector_symbol_parts(kind, x, y, s, ink, floor, width)
        if vector_parts:
            parts.extend(vector_parts)
        else:
            text(symbol_icon(kind).strip()[:2], factor=0.7)

    if abs(rotation % 360) < 0.01:
        return parts
    return [f'<g transform="rotate({rotation:.2f} {x:.2f} {y:.2f})">', *parts, "</g>"]


def escape_xml(value: str) -> str:
    return (
        value.replace("&", "&amp;")
        .replace("<", "&lt;")
        .replace(">", "&gt;")
        .replace('"', "&quot;")
    )


def svg_points(points: list[tuple[float, float]]) -> str:
    return " ".join(f"{x:.2f},{y:.2f}" for x, y in points)


_CANVAS_SIZE_CACHE: OrderedDict[str, tuple[float, float]] = OrderedDict()
_FLOOR_POLYGON_POINTS_CACHE: OrderedDict[str, tuple[tuple[float, float], ...]] = (
    OrderedDict()
)
_FLOOR_GRID_SEGMENTS_CACHE: OrderedDict[
    str, tuple[tuple[float, float, float, float], ...]
] = OrderedDict()
_EXPANDED_FLOOR_POLYGON_POINTS_CACHE: OrderedDict[
    str, tuple[tuple[float, float], ...]
] = OrderedDict()
_UNDERLAY_SOURCE_IMAGE_CACHE: OrderedDict[str, Any] = OrderedDict()
_UNDERLAY_TRANSFORM_IMAGE_CACHE: OrderedDict[str, Any] = OrderedDict()
_TK_UNDERLAY_PHOTO_CACHE: OrderedDict[str, Any] = OrderedDict()
_STYLED_CUSTOM_SYMBOL_IMAGE_CACHE: OrderedDict[str, Any] = OrderedDict()
_TK_SYMBOL_PHOTO_CACHE: OrderedDict[str, Any] = OrderedDict()


def stable_cache_hash(value: Any) -> str:
    return hashlib.sha1(
        json.dumps(value, sort_keys=True, default=str).encode("utf-8")
    ).hexdigest()


def cache_get(cache: OrderedDict[str, Any], key: str):
    if key not in cache:
        return None
    value = cache.pop(key)
    cache[key] = value
    return value


def cache_put(cache: OrderedDict[str, Any], key: str, value: Any, limit: int) -> Any:
    if key in cache:
        cache.pop(key)
    elif len(cache) >= limit:
        cache.popitem(last=False)
    cache[key] = value
    return value


def path_cache_token(path: Path) -> tuple[str, int, int] | tuple[str, str]:
    try:
        stat = path.stat()
        return str(path.resolve()), int(stat.st_mtime_ns), int(stat.st_size)
    except OSError:
        return str(path), "missing"


def image_copy_or_none(image):
    return image.copy() if image is not None and hasattr(image, "copy") else image


def performance_cache_stats() -> dict[str, int]:
    return {
        "canvas_size": len(_CANVAS_SIZE_CACHE),
        "floor_polygons": len(_FLOOR_POLYGON_POINTS_CACHE),
        "floor_grid_segments": len(_FLOOR_GRID_SEGMENTS_CACHE),
        "floor_expanded_polygons": len(_EXPANDED_FLOOR_POLYGON_POINTS_CACHE),
        "underlay_sources": len(_UNDERLAY_SOURCE_IMAGE_CACHE),
        "underlay_transforms": len(_UNDERLAY_TRANSFORM_IMAGE_CACHE),
        "tk_underlay_photos": len(_TK_UNDERLAY_PHOTO_CACHE),
        "styled_custom_symbols": len(_STYLED_CUSTOM_SYMBOL_IMAGE_CACHE),
        "tk_symbol_photos": len(_TK_SYMBOL_PHOTO_CACHE),
        "layer_indices": len(_LAYER_INDEX_CACHE),
    }


def clear_performance_caches() -> None:
    for cache in (
        _CANVAS_SIZE_CACHE,
        _FLOOR_POLYGON_POINTS_CACHE,
        _FLOOR_GRID_SEGMENTS_CACHE,
        _EXPANDED_FLOOR_POLYGON_POINTS_CACHE,
        _UNDERLAY_SOURCE_IMAGE_CACHE,
        _UNDERLAY_TRANSFORM_IMAGE_CACHE,
        _TK_UNDERLAY_PHOTO_CACHE,
        _STYLED_CUSTOM_SYMBOL_IMAGE_CACHE,
        _TK_SYMBOL_PHOTO_CACHE,
        _LAYER_INDEX_CACHE,
    ):
        cache.clear()
    cached_custom_symbol_image.cache_clear()
    cached_embedded_custom_symbol_image.cache_clear()


def canvas_size_cache_key(
    project: dict[str, Any], scale: float, include_legend: bool
) -> str:
    settings = project["settings"]
    context = render_context(project)
    visible_objects = []
    for obj in project.get("objects", []):
        if obj.get("type") == "legend" and not include_legend:
            continue
        if should_render_object(project, obj, for_export=False, context=context):
            visible_objects.append(obj)
    payload = {
        "scale": round(float(scale), 5),
        "includeLegend": include_legend,
        "settings": {
            key: settings.get(key)
            for key in (
                "width",
                "height",
                "cellSize",
                "showLegend",
                "cellScale",
                "cellScaleUnit",
            )
        },
        "layers": [
            {
                "id": layer.get("id"),
                "visible": layer.get("visible", True),
            }
            for layer in project.get("layers", [])
        ],
        "customSymbols": project.get("customSymbols", {}),
        "legendCategories": project.get("legendCategories", {}),
        "objects": visible_objects,
    }
    return stable_cache_hash(payload)


def canvas_size(
    project: dict[str, Any], scale: float = 1.0, include_legend: bool | None = None
) -> tuple[float, float]:
    settings = project["settings"]
    if include_legend is None:
        include_legend = settings.get("showLegend", True)
    key = canvas_size_cache_key(project, scale, bool(include_legend))
    cached = cache_get(_CANVAS_SIZE_CACHE, key)
    if cached is not None:
        return cached
    max_x = float(settings["width"])
    max_y = float(settings["height"])
    context = render_context(project)
    for obj in project.get("objects", []):
        if obj.get("type") == "legend" and not include_legend:
            continue
        if not should_render_object(project, obj, for_export=False, context=context):
            continue
        x, y, w, h = (
            legend_bounds(project, obj) if obj.get("type") == "legend" else bounds(obj)
        )
        max_x = max(max_x, x + w + 1)
        max_y = max(max_y, y + h + 1)
    result = max_x * settings["cellSize"] * scale, max_y * settings["cellSize"] * scale
    cache_put(_CANVAS_SIZE_CACHE, key, result, CANVAS_SIZE_CACHE_LIMIT)
    return result


def bounds(obj: dict[str, Any]) -> tuple[float, float, float, float]:
    if obj["type"] == "symbol":
        size = float(obj.get("size", 1))
        return obj["x"] - size / 2, obj["y"] - size / 2, size, size
    if obj["type"] == "text":
        size = float(obj.get("size", 1))
        width = obj.get("width", 0) or max(
            1.0, len(str(obj.get("text", ""))) * size * 0.55
        )
        height = obj.get("height", 0) or max(
            size, (str(obj.get("text", "")).count("\n") + 1) * size * 1.15
        )
        if obj.get("align") == "left" or obj.get("textRole") == "note":
            return obj["x"], obj["y"], width, height
        if obj.get("align") == "right":
            return obj["x"] - width, obj["y"], width, height
        return obj["x"] - width / 2, obj["y"], width, height
    if obj["type"] == "diagonal_corridor":
        thickness = float(obj.get("width", 1))
        x1, y1 = float(obj["x"]), float(obj["y"])
        x2, y2 = float(obj["x2"]), float(obj["y2"])
        return (
            min(x1, x2) - thickness / 2,
            min(y1, y2) - thickness / 2,
            abs(x2 - x1) + thickness,
            abs(y2 - y1) + thickness,
        )
    if obj["type"] == "legend":
        return obj["x"], obj["y"], obj["width"], obj["height"]
    if is_polygon_room(obj):
        if has_floor_rotation(obj):
            return tuple_points_bounds(floor_polygon_points(obj, 1.0))
        return bounds_from_points(validate_shape_points(obj.get("points")))
    if obj["type"] in RECTLIKE_TYPES and has_floor_rotation(obj):
        return tuple_points_bounds(floor_polygon_points(obj, 1.0))
    if obj["type"] == "shape":
        line_width = float(obj.get("lineWidth", 0.12))
        if obj.get("kind") == "line":
            x1, y1 = float(obj["x"]), float(obj["y"])
            x2, y2 = float(obj["x2"]), float(obj["y2"])
            if obj.get("curve", False):
                cx, cy = curved_line_control((x1, y1), (x2, y2))
                left, top = min(x1, x2, cx), min(y1, y2, cy)
                right, bottom = max(x1, x2, cx), max(y1, y2, cy)
            else:
                left, top = min(x1, x2), min(y1, y2)
                right, bottom = max(x1, x2), max(y1, y2)
            padding = max(0.15, line_width / 2)
            return (
                left - padding,
                top - padding,
                right - left + padding * 2,
                bottom - top + padding * 2,
            )
        if obj.get("kind") == "polygon" and obj.get("points"):
            point_bounds = bounds_from_points(validate_shape_points(obj.get("points")))
            padding = max(0.0, line_width / 2)
            return (
                point_bounds[0] - padding,
                point_bounds[1] - padding,
                point_bounds[2] + padding * 2,
                point_bounds[3] + padding * 2,
            )
        return obj["x"], obj["y"], obj["width"], obj["height"]
    return obj["x"], obj["y"], obj["width"], obj["height"]


def spatial_index_cell(value: float, bucket_size: float) -> int:
    return int(math.floor(value / max(0.01, bucket_size)))


def build_object_index(objects: list[dict[str, Any]]) -> ObjectIndex:
    object_by_id: dict[str, dict[str, Any]] = {}
    bounds_by_id: dict[str, tuple[float, float, float, float]] = {}
    objects_by_layer: dict[str, list[dict[str, Any]]] = {}
    objects_by_group: dict[str, list[dict[str, Any]]] = {}
    order_by_id: dict[str, int] = {}
    for order, obj in enumerate(objects, start=1):
        obj_id = str(obj.get("id") or "")
        if obj_id:
            object_by_id[obj_id] = obj
            order_by_id[obj_id] = order
            try:
                bounds_by_id[obj_id] = bounds(obj)
            except Exception:
                pass
        layer_id = str(obj.get("layer") or normalize_layer_id(None, obj.get("type")))
        objects_by_layer.setdefault(layer_id, []).append(obj)
        group = obj.get("group")
        if group:
            objects_by_group.setdefault(str(group), []).append(obj)
    return ObjectIndex(
        object_by_id=object_by_id,
        bounds_by_id=bounds_by_id,
        objects_by_layer=objects_by_layer,
        objects_by_group=objects_by_group,
        order_by_id=order_by_id,
    )


def build_spatial_index(
    objects: list[dict[str, Any]],
    bucket_size: float = 8.0,
    bounds_by_id: dict[str, tuple[float, float, float, float]] | None = None,
) -> dict[tuple[int, int], list[dict[str, Any]]]:
    index: dict[tuple[int, int], list[dict[str, Any]]] = {}
    for obj in objects:
        try:
            obj_id = str(obj.get("id") or "")
            cached = bounds_by_id.get(obj_id) if bounds_by_id is not None else None
            left, top, width, height = cached if cached is not None else bounds(obj)
        except Exception:
            continue
        x1 = spatial_index_cell(left, bucket_size)
        y1 = spatial_index_cell(top, bucket_size)
        x2 = spatial_index_cell(left + width, bucket_size)
        y2 = spatial_index_cell(top + height, bucket_size)
        for gx in range(x1, x2 + 1):
            for gy in range(y1, y2 + 1):
                index.setdefault((gx, gy), []).append(obj)
    return index


def spatial_index_query(
    index: dict[tuple[int, int], list[dict[str, Any]]],
    x: float,
    y: float,
    bucket_size: float = 8.0,
) -> list[dict[str, Any]]:
    return list(index.get((spatial_index_cell(x, bucket_size), spatial_index_cell(y, bucket_size)), []))


def topmost_hit_object(
    project: dict[str, Any],
    x: float,
    y: float,
    *,
    tolerance: float = 0.35,
    index: dict[tuple[int, int], list[dict[str, Any]]] | None = None,
    bucket_size: float = 8.0,
    bounds_by_id: dict[str, tuple[float, float, float, float]] | None = None,
    is_visible=None,
    is_locked=None,
) -> dict[str, Any] | None:
    objects = project.get("objects", [])
    if index is not None:
        candidates = []
        for gx in range(
            spatial_index_cell(x - tolerance, bucket_size),
            spatial_index_cell(x + tolerance, bucket_size) + 1,
        ):
            for gy in range(
                spatial_index_cell(y - tolerance, bucket_size),
                spatial_index_cell(y + tolerance, bucket_size) + 1,
            ):
                candidates.extend(index.get((gx, gy), []))
    else:
        candidates = objects
    candidate_ids = {id(obj) for obj in candidates}
    for obj in reversed(objects):
        if index is not None and id(obj) not in candidate_ids:
            continue
        if is_visible is not None and not is_visible(obj):
            continue
        if is_locked is not None and is_locked(obj):
            continue
        obj_id = str(obj.get("id") or "")
        cached = bounds_by_id.get(obj_id) if bounds_by_id is not None else None
        bx, by, bw, bh = cached if cached is not None else bounds(obj)
        if (
            bx - tolerance <= x <= bx + bw + tolerance
            and by - tolerance <= y <= by + bh + tolerance
        ):
            if is_polygon_room(obj) and not point_in_polygon(
                x, y, floor_polygon_points(obj, 1.0)
            ):
                continue
            return obj
    return None


def project_static_cache_signature(
    project: dict[str, Any], layer_id: str, scale: int
) -> str:
    layer_objects = [
        obj
        for obj in project.get("objects", [])
        if obj.get("layer", normalize_layer_id(None, obj.get("type"))) == layer_id
    ]
    payload = {
        "scale": int(scale),
        "settings": {
            key: project.get("settings", {}).get(key)
            for key in (
                "width",
                "height",
                "cellSize",
                "backgroundColor",
                "gridColor",
                "floorColor",
                "floorOutlineColor",
                "showFloorOutlines",
                "exportGrid",
                "mapMode",
                "hexOrientation",
            )
        },
        "objects": layer_objects,
    }
    return hashlib.sha1(json.dumps(payload, sort_keys=True).encode("utf-8")).hexdigest()


def tk_static_canvas_signature(
    project: dict[str, Any], zoom: float, context: RenderContext | None = None
) -> str:
    settings = project.get("settings", {})
    underlay_state = [
        {
            "id": underlay.get("id"),
            "path": underlay.get("path"),
            "embeddedData": bool(underlay.get("embeddedData")),
            "x": underlay.get("x"),
            "y": underlay.get("y"),
            "width": underlay.get("width"),
            "height": underlay.get("height"),
            "rotation": underlay.get("rotation"),
            "opacity": underlay.get("opacity"),
            "visible": underlay.get("visible", True),
        }
        for underlay in project.get("underlays", [])
    ]
    payload = {
        "zoom": round(float(zoom), 4),
        "canvasSize": canvas_size(project, zoom),
        "backgroundVisible": project_layer_visible(
            project, "background", context or render_context(project)
        ),
        "settings": {
            key: settings.get(key)
            for key in (
                "width",
                "height",
                "cellSize",
                "backgroundColor",
                "gridColor",
                "showMainGrid",
                "showSubGrid",
                "snapStep",
                "showCoordinates",
                "mapMode",
                "hexOrientation",
                "showHexCoordinates",
                "hexCoordinateStyle",
                "underlayVisible",
                "underlayOpacity",
            )
        },
        "underlays": underlay_state,
    }
    return hashlib.sha1(json.dumps(payload, sort_keys=True).encode("utf-8")).hexdigest()


def tk_static_layer_signature(
    project: dict[str, Any],
    layer_id: str,
    zoom: float,
    context: RenderContext | None = None,
) -> str:
    settings = project.get("settings", {})
    layer_objects = [
        obj
        for obj in project.get("objects", [])
        if obj.get("layer", normalize_layer_id(None, obj.get("type"))) == layer_id
        and should_render_object(project, obj, for_export=False, context=context)
    ]
    payload = {
        "layer": layer_id,
        "zoom": round(float(zoom), 4),
        "objects": layer_objects,
        "layerOpacity": project_layer_opacity(project, layer_id, context),
        "settings": {
            key: settings.get(key)
            for key in (
                "cellSize",
                "floorColor",
                "gridColor",
                "textColor",
                "legendColor",
                "floorOutlineColor",
                "showFloorOutlines",
                "showRoomStatus",
                "roomStatusGmOnly",
                "styleTemplate",
                "mapMode",
                "hexOrientation",
            )
        },
    }
    return hashlib.sha1(json.dumps(payload, sort_keys=True).encode("utf-8")).hexdigest()


def draw_tk_static_canvas_background(
    canvas: tk.Canvas,
    project: dict[str, Any],
    zoom: float,
    context: RenderContext | None = None,
) -> None:
    settings = project["settings"]
    width, height = canvas_size(project, zoom)
    if project_layer_visible(project, "background", context):
        canvas.create_rectangle(
            0, 0, width, height, fill=settings["backgroundColor"], outline=""
        )
        draw_tk_grid(canvas, settings, zoom)
        draw_tk_underlays(canvas, project, zoom)
    else:
        canvas.create_rectangle(0, 0, width, height, fill="#f9fcfd", outline="")
    draw_tk_workspace_bounds(canvas, settings, zoom)


def draw_tk_static_layer(
    canvas: tk.Canvas,
    project: dict[str, Any],
    layer_id: str,
    zoom: float,
    context: RenderContext | None = None,
) -> None:
    layer_project = {**project}
    layer_project["objects"] = [
        obj
        for obj in project.get("objects", [])
        if obj.get("layer", normalize_layer_id(None, obj.get("type"))) == layer_id
    ]
    render_tk(
        canvas,
        layer_project,
        zoom,
        set(),
        None,
        None,
        None,
        preview_for_export=False,
        context=context or render_context(project),
        draw_static_background=False,
    )


def render_tk(
    canvas: tk.Canvas,
    project: dict[str, Any],
    zoom: float,
    selected_ids: set[str],
    primary_selected_id: str | None,
    draft: Draft | None,
    selection_box: tuple[float, float, float, float] | None,
    viewport: tuple[float, float, float, float] | None = None,
    preview_for_export: bool = False,
    context: RenderContext | None = None,
    draw_static_background: bool = True,
    skip_layer_ids: set[str] | None = None,
) -> None:
    settings = project["settings"]
    context = context or render_context(project)
    if draw_static_background:
        canvas._image_refs = []
        draw_tk_static_canvas_background(canvas, project, zoom, context)
    skip_layer_ids = skip_layer_ids or set()
    renderable_objects = []
    for obj in project["objects"]:
        if obj.get("layer", normalize_layer_id(None, obj.get("type"))) in skip_layer_ids:
            continue
        if not should_render_object(
            project, obj, for_export=preview_for_export, context=context
        ):
            continue
        if (
            viewport
            and obj.get("id") not in selected_ids
            and not rects_overlap(bounds(obj), viewport)
        ):
            continue
        renderable_objects.append(obj)
    draw_tk_floor_objects(
        canvas,
        settings,
        [obj for obj in renderable_objects if obj.get("type") in FLOOR_TYPES],
        zoom,
    )
    if settings.get("showRoomStatus", True) and (
        not settings.get("roomStatusGmOnly", True) or not preview_for_export
    ):
        draw_tk_room_status(
            canvas,
            settings,
            [
                obj
                for obj in renderable_objects
                if obj.get("type") in {"room", "round", "cave"}
            ],
            zoom,
        )
    for obj in renderable_objects:
        if obj.get("type") in FLOOR_TYPES:
            continue
        draw_tk_object(canvas, project, settings, obj, zoom)
    if draft:
        if draft.kind in {"cave_corridor", "room_polygon"}:
            points = draft_polygon_points(draft, include_preview=True)
            c = settings["cellSize"] * zoom
            color = settings.get("selectionColor", SELECT)
            if draft.kind == "room_polygon":
                if len(points) >= 3:
                    preview_room = polygon_room_from_points(points)
                    preview_room["id"] = "draft_room_polygon"
                    draw_tk_floor_objects(
                        canvas,
                        settings,
                        [preview_room],
                        zoom,
                    )
                elif len(points) >= 2:
                    canvas.create_line(
                        flatten_points([(gx * c, gy * c) for gx, gy in points]),
                        fill=color,
                        width=max(2, int(c * 0.08)),
                        dash=(5, 3),
                    )
            radius = max(3, min(8, c * 0.2))
            for index, (gx, gy) in enumerate(points):
                px, py = gx * c, gy * c
                canvas.create_oval(
                    px - radius,
                    py - radius,
                    px + radius,
                    py + radius,
                    fill=color,
                    outline=settings.get("gridColor", BLUE),
                    width=1,
                )
                if index == 0:
                    canvas.create_oval(
                        px - radius * 1.8,
                        py - radius * 1.8,
                        px + radius * 1.8,
                        py + radius * 1.8,
                        outline=color,
                        width=2,
                    )
        elif draft.kind in SHAPE_TOOLS:
            draw_tk_shape(
                canvas,
                settings,
                shape_from_draft_data(draft, include_preview=True),
                zoom,
                dash=(4, 3),
            )
        elif (
            draft.kind == "corridor"
            and draft.x2 is not None
            and draft.y2 is not None
            and draft.x != draft.x2
            and draft.y != draft.y2
        ):
            draw_tk_diagonal_corridor(
                canvas,
                settings,
                {
                    "x": draft.x,
                    "y": draft.y,
                    "x2": draft.x2,
                    "y2": draft.y2,
                    "width": 1,
                },
                zoom,
            )
        elif draft.kind == "corridor" and draft.x2 is not None and draft.y2 is not None:
            draw_tk_rectlike(
                canvas,
                settings,
                {
                    "type": "corridor",
                    "x": min(draft.x, draft.x2),
                    "y": min(draft.y, draft.y2),
                    "width": max(0.25, abs(draft.x2 - draft.x)),
                    "height": max(0.25, abs(draft.y2 - draft.y)),
                },
                zoom,
                stipple="gray50",
            )
        else:
            draw_tk_rectlike(canvas, settings, draft.__dict__, zoom, stipple="gray50")
    selected_objects = [
        obj
        for obj in project["objects"]
        if obj["id"] in selected_ids
        and should_render_object(
            project, obj, for_export=preview_for_export, context=context
        )
    ]
    for obj in selected_objects:
        draw_tk_selection(
            canvas,
            settings,
            obj,
            zoom,
            show_handles=len(selected_objects) == 1
            and obj["id"] == primary_selected_id,
            multi_select=len(selected_objects) > 1,
        )
    if len(selected_objects) > 1:
        box = union_bounds(selected_objects)
        if box:
            draw_tk_bounds(
                canvas,
                {**settings, "selectionColor": "#5aa7d6"},
                box,
                zoom,
                dash=(3, 2),
            )
    if selection_box:
        x1, y1, x2, y2 = selection_box
        c = settings["cellSize"] * zoom
        canvas.create_rectangle(
            x1 * c,
            y1 * c,
            x2 * c,
            y2 * c,
            outline=settings.get("selectionColor", SELECT),
            width=2,
            dash=(2, 2),
        )


def draw_tk_workspace_bounds(
    canvas: tk.Canvas, settings: dict[str, Any], zoom: float
) -> None:
    c = settings["cellSize"] * zoom
    width = settings["width"] * c
    height = settings["height"] * c
    ink = settings.get("gridColor", BLUE)
    edge = soften_color(ink, 0.25)
    shadow = "#9aa7ad"
    canvas.create_line(3, height - 2, width - 2, height - 2, fill=shadow, width=2)
    canvas.create_line(width - 2, 3, width - 2, height - 2, fill=shadow, width=2)
    canvas.create_rectangle(
        0, 0, width, height, outline=edge, width=max(2, int(c * 0.06))
    )
    canvas.create_rectangle(1, 1, width - 1, height - 1, outline="#ffffff", width=1)
    label = f"Map {settings['width']} x {settings['height']} cells"
    text_id = canvas.create_text(
        max(8, c * 0.25),
        max(8, c * 0.25),
        text=label,
        anchor="nw",
        fill=ink,
        font=("Segoe UI", max(7, int(c * 0.34)), "bold"),
    )
    box = canvas.bbox(text_id)
    if box:
        rect_id = canvas.create_rectangle(
            box[0] - 4,
            box[1] - 2,
            box[2] + 4,
            box[3] + 2,
            fill=soften_color(settings.get("backgroundColor", WHITE), 0.1),
            outline=ink,
        )
        canvas.tag_raise(text_id, rect_id)


def draw_tk_grid(canvas: tk.Canvas, settings: dict[str, Any], zoom: float) -> None:
    c = settings["cellSize"] * zoom
    width = settings["width"] * c
    height = settings["height"] * c
    if settings.get("mapMode") == "Hexmap":
        draw_tk_hex_grid(canvas, settings, zoom)
        return
    if settings.get("showSubGrid", True):
        step = normalize_snap_step(settings.get("snapStep", 1.0))
        if step < 1:
            sub = c * step
            color = soften_color(settings["backgroundColor"], 0.35)
            count_x = int(settings["width"] / step) + 1
            count_y = int(settings["height"] / step) + 1
            for index in range(count_x + 1):
                x = index * sub
                canvas.create_line(x, 0, x, height, fill=color)
            for index in range(count_y + 1):
                y = index * sub
                canvas.create_line(0, y, width, y, fill=color)
    if settings.get("showMainGrid", True):
        color = soften_color(settings["backgroundColor"], 0.55)
        for x in range(settings["width"] + 1):
            px = x * c
            canvas.create_line(px, 0, px, height, fill=color)
        for y in range(settings["height"] + 1):
            py = y * c
            canvas.create_line(0, py, width, py, fill=color)
    if settings.get("showCoordinates", False):
        draw_tk_coordinates(canvas, settings, zoom)


def hex_points(cx: float, cy: float, radius: float, orientation: str) -> list[tuple[float, float]]:
    offset = 0 if orientation == "pointy" else math.pi / 6
    return [
        (cx + math.cos(offset + math.tau * index / 6) * radius,
         cy + math.sin(offset + math.tau * index / 6) * radius)
        for index in range(6)
    ]


def draw_tk_hex_grid(canvas: tk.Canvas, settings: dict[str, Any], zoom: float) -> None:
    c = settings["cellSize"] * zoom
    width = settings["width"] * c
    height = settings["height"] * c
    color = soften_color(settings["backgroundColor"], 0.55)
    orientation = settings.get("hexOrientation", "pointy")
    radius = c / math.sqrt(3) if orientation == "pointy" else c / 2
    for row in range(settings["height"] + 2):
        for column in range(settings["width"] + 2):
            cx, cy = hex_cell_center(column, row, c, orientation)
            if cx < -c or cy < -c or cx > width + c or cy > height + c:
                continue
            points = hex_points(cx, cy, radius, orientation)
            canvas.create_polygon(flatten_points(points), outline=color, fill="")
            if settings.get("showHexCoordinates", False):
                canvas.create_text(
                    cx,
                    cy,
                    text=hex_coordinate_label(
                        column, row, settings.get("hexCoordinateStyle", "axial")
                    ),
                    fill=settings.get("gridColor", BLUE),
                    font=("Segoe UI", max(6, int(c * 0.22))),
                )
    if settings.get("showCoordinates", False):
        draw_tk_coordinates(canvas, settings, zoom)


def underlay_source_cache_key(underlay: dict[str, Any]) -> str:
    if underlay.get("embeddedData"):
        return "embedded:" + hashlib.sha1(
            str(underlay.get("embeddedData") or "").encode("utf-8")
        ).hexdigest()
    path = Path(str(underlay.get("path") or ""))
    return "path:" + stable_cache_hash(path_cache_token(path))


def transformed_underlay_cache_key(
    underlay: dict[str, Any], width: int, height: int, opacity: float
) -> str:
    return stable_cache_hash(
        {
            "source": underlay_source_cache_key(underlay),
            "width": int(width),
            "height": int(height),
            "rotation": round(float(underlay.get("rotation", 0) or 0), 3),
            "opacity": round(float(opacity), 4),
        }
    )


def load_underlay_image(underlay: dict[str, Any]):
    if Image is None:
        return None
    key = underlay_source_cache_key(underlay)
    cached = cache_get(_UNDERLAY_SOURCE_IMAGE_CACHE, key)
    if cached is not None:
        return image_copy_or_none(cached)
    try:
        if underlay.get("embeddedData"):
            image = Image.open(
                io.BytesIO(base64.b64decode(underlay["embeddedData"]))
            ).convert("RGBA")
            cache_put(
                _UNDERLAY_SOURCE_IMAGE_CACHE,
                key,
                image.copy(),
                UNDERLAY_IMAGE_CACHE_LIMIT,
            )
            return image
        path = str(underlay.get("path") or "")
        if path and Path(path).exists():
            image = Image.open(path).convert("RGBA")
            cache_put(
                _UNDERLAY_SOURCE_IMAGE_CACHE,
                key,
                image.copy(),
                UNDERLAY_IMAGE_CACHE_LIMIT,
            )
            return image
    except Exception:
        return None
    return None


def transformed_underlay_image(
    underlay: dict[str, Any], width: int, height: int, opacity: float
):
    if Image is None:
        return None
    key = transformed_underlay_cache_key(underlay, width, height, opacity)
    cached = cache_get(_UNDERLAY_TRANSFORM_IMAGE_CACHE, key)
    if cached is not None:
        return image_copy_or_none(cached)
    image = load_underlay_image(underlay)
    if image is None:
        return None
    image = image.resize((max(1, int(width)), max(1, int(height))))
    if underlay.get("rotation"):
        image = image.rotate(
            -float(underlay.get("rotation", 0)),
            resample=Image.Resampling.BICUBIC,
            expand=True,
        )
    image = image_with_opacity(image, opacity)
    cache_put(
        _UNDERLAY_TRANSFORM_IMAGE_CACHE,
        key,
        image.copy(),
        UNDERLAY_IMAGE_CACHE_LIMIT,
    )
    return image


def tk_underlay_photo_image(
    underlay: dict[str, Any], width: int, height: int, opacity: float
):
    if ImageTk is None:
        return None
    key = "tk:" + transformed_underlay_cache_key(underlay, width, height, opacity)
    cached = cache_get(_TK_UNDERLAY_PHOTO_CACHE, key)
    if cached is not None:
        return cached
    image = transformed_underlay_image(underlay, width, height, opacity)
    if image is None:
        return None
    photo = ImageTk.PhotoImage(image)
    return cache_put(_TK_UNDERLAY_PHOTO_CACHE, key, photo, UNDERLAY_IMAGE_CACHE_LIMIT)


def draw_tk_underlays(canvas: tk.Canvas, project: dict[str, Any], zoom: float) -> None:
    settings = project["settings"]
    if not settings.get("underlayVisible", True):
        return
    c = settings["cellSize"] * zoom
    for underlay in project.get("underlays", []):
        if not underlay.get("visible", True):
            continue
        x = underlay["x"] * c
        y = underlay["y"] * c
        w = max(1, int(underlay["width"] * c))
        h = max(1, int(underlay["height"] * c))
        photo = tk_underlay_photo_image(
            underlay,
            w,
            h,
            underlay.get("opacity", settings.get("underlayOpacity", 0.45)),
        )
        if photo is None:
            canvas.create_rectangle(
                x, y, x + w, y + h, outline=settings["gridColor"], dash=(5, 4)
            )
            canvas.create_text(
                x + w / 2,
                y + h / 2,
                text=underlay.get("name", "Underlay"),
                fill=settings["gridColor"],
            )
            continue
        canvas.create_image(x, y, image=photo, anchor="nw")
        refs = getattr(canvas, "_image_refs", [])
        refs.append(photo)
        canvas._image_refs = refs


def grid_column_label(index: int) -> str:
    index = max(1, int(index))
    label = ""
    while index:
        index, remainder = divmod(index - 1, 26)
        label = chr(ord("A") + remainder) + label
    return label


def draw_tk_coordinates(
    canvas: tk.Canvas, settings: dict[str, Any], zoom: float
) -> None:
    c = settings["cellSize"] * zoom
    width = settings["width"] * c
    height = settings["height"] * c
    ink = settings.get("gridColor", BLUE)
    bg = soften_color(settings.get("backgroundColor", WHITE), 0.2)
    font_size = max(6, int(c * 0.38))
    font = ("Segoe UI", font_size, "bold")
    for column in range(settings["width"]):
        x = column * c + c / 2
        label = grid_column_label(column + 1)
        canvas.create_text(x, max(6, c * 0.28), text=label, fill=ink, font=font)
        canvas.create_text(
            x, height - max(6, c * 0.28), text=label, fill=ink, font=font
        )
    for row in range(settings["height"]):
        y = row * c + c / 2
        label = str(row + 1)
        canvas.create_text(max(8, c * 0.32), y, text=label, fill=ink, font=font)
        canvas.create_text(width - max(8, c * 0.32), y, text=label, fill=ink, font=font)
    canvas.create_rectangle(
        0, 0, width, height, outline=bg, width=max(1, int(c * 0.04))
    )


def draw_tk_zones(canvas: tk.Canvas, project: dict[str, Any], zoom: float) -> None:
    settings = project["settings"]
    if not settings.get("showZones", True):
        return
    c = settings["cellSize"] * zoom
    for zone in project.get("zones", []):
        if not zone.get("visible", True):
            continue
        x = zone["x"] * c
        y = zone["y"] * c
        w = zone["width"] * c
        h = zone["height"] * c
        color = zone.get("color") or settings.get("selectionColor", SELECT)
        canvas.create_rectangle(
            x, y, x + w, y + h, outline=color, width=max(1, int(c * 0.08)), dash=(6, 4)
        )
        canvas.create_text(
            x + max(4, c * 0.25),
            y + max(8, c * 0.35),
            text=str(zone.get("name", "Zone")),
            anchor="w",
            fill=color,
            font=("Segoe UI", max(7, int(c * 0.42)), "bold"),
        )


def draw_tk_floor_overlay(
    canvas: tk.Canvas, project: dict[str, Any], zoom: float
) -> None:
    settings = project["settings"]
    overlay_id = str(settings.get("floorOverlayMapId") or "")
    if not overlay_id:
        return
    record = next(
        (item for item in project.get("maps", []) if item.get("id") == overlay_id), None
    )
    if not record:
        return
    overlay_settings = validate_settings(record.get("settings", settings))
    overlay_settings["gridColor"] = soften_color(
        str(settings.get("gridColor", BLUE)), 0.55
    )
    overlay_settings["floorColor"] = soften_color(
        str(settings.get("floorColor", WHITE)), 0.25
    )
    overlay_project = json_clone(project)
    overlay_project["settings"] = overlay_settings
    overlay_project["objects"] = [
        obj
        for obj in json_clone(record.get("objects", []))
        if obj.get("type") != "legend"
    ]
    for obj in overlay_project["objects"]:
        if obj.get("type") == "shape":
            obj["opacity"] = min(
                coerce_float(obj.get("opacity"), 1.0),
                coerce_float(settings.get("floorOverlayOpacity"), 0.35),
            )
        draw_tk_object(canvas, overlay_project, overlay_settings, obj, zoom)


def draw_tk_export_frames(
    canvas: tk.Canvas, project: dict[str, Any], zoom: float
) -> None:
    settings = project["settings"]
    c = settings["cellSize"] * zoom
    color = settings.get("selectionColor", SELECT)
    active_frame = settings.get("activeExportFrame")
    for frame in project.get("exportFrames", []):
        x = frame["x"] * c
        y = frame["y"] * c
        w = frame["width"] * c
        h = frame["height"] * c
        is_active = frame.get("id") == active_frame
        width = max(2, int(c * (0.1 if is_active else 0.07)))
        dash_options = {} if is_active else {"dash": (10, 5)}
        canvas.create_rectangle(x, y, x + w, y + h, outline=color, width=width + 2)
        canvas.create_rectangle(
            x,
            y,
            x + w,
            y + h,
            fill=color,
            stipple="gray12",
            outline=color,
            width=width,
            **dash_options,
        )
        label = f"{frame.get('name', 'Export')}  {frame['width']} x {frame['height']}"
        text_x = x + max(4, c * 0.25)
        text_y = y + max(8, c * 0.35)
        text_id = canvas.create_text(
            text_x,
            text_y,
            text=label,
            anchor="w",
            fill=color,
            font=("Segoe UI", max(7, int(c * 0.38)), "bold"),
        )
        box = canvas.bbox(text_id)
        if box:
            rect_id = canvas.create_rectangle(
                box[0] - 4,
                box[1] - 2,
                box[2] + 4,
                box[3] + 2,
                fill="#fffdf2",
                outline=color,
            )
            canvas.tag_raise(text_id, rect_id)


def draw_tk_markers(canvas: tk.Canvas, project: dict[str, Any], zoom: float) -> None:
    settings = project["settings"]
    c = settings["cellSize"] * zoom
    color = settings.get("selectionColor", SELECT)
    for marker in project.get("markers", []):
        x = marker["x"] * c
        y = marker["y"] * c
        r = max(5, c * 0.22)
        canvas.create_oval(x - r, y - r, x + r, y + r, outline=color, width=2)
        canvas.create_line(x - r * 1.4, y, x + r * 1.4, y, fill=color, width=2)
        canvas.create_line(x, y - r * 1.4, x, y + r * 1.4, fill=color, width=2)
        canvas.create_text(
            x + r * 1.6,
            y,
            text=str(marker.get("name", "Marker")),
            anchor="w",
            fill=color,
            font=("Segoe UI", max(7, int(c * 0.38)), "bold"),
        )


def draw_tk_print_grid(
    canvas: tk.Canvas, settings: dict[str, Any], zoom: float
) -> None:
    if not settings.get("showPrintGrid", False):
        return
    c = settings["cellSize"] * zoom
    width = settings["width"] * c
    height = settings["height"] * c
    page_w = max(1, int(settings.get("print_page_width_cells", 24))) * c
    page_h = max(1, int(settings.get("print_page_height_cells", 32))) * c
    margin = max(0, int(settings.get("print_margin_cells", 1))) * c
    color = "#8c6b23"
    x = page_w
    while x < width:
        canvas.create_line(x, 0, x, height, fill=color, width=2, dash=(12, 6))
        x += page_w
    y = page_h
    while y < height:
        canvas.create_line(0, y, width, y, fill=color, width=2, dash=(12, 6))
        y += page_h
    if margin:
        canvas.create_rectangle(
            margin,
            margin,
            max(margin, width - margin),
            max(margin, height - margin),
            outline=color,
            width=1,
            dash=(4, 4),
        )


def active_focus_zone(
    project: dict[str, Any],
    selected_ids: set[str],
    mouse_grid: tuple[float, float] | None,
) -> dict[str, Any] | None:
    zones = [zone for zone in project.get("zones", []) if zone.get("visible", True)]
    if not zones:
        return None
    for obj in project.get("objects", []):
        if obj.get("id") not in selected_ids:
            continue
        x, y, w, h = bounds(obj)
        cx, cy = x + w / 2, y + h / 2
        zone = next(
            (
                item
                for item in zones
                if item["x"] <= cx <= item["x"] + item["width"]
                and item["y"] <= cy <= item["y"] + item["height"]
            ),
            None,
        )
        if zone:
            return zone
    if mouse_grid:
        mx, my = mouse_grid
        zone = next(
            (
                item
                for item in zones
                if item["x"] <= mx <= item["x"] + item["width"]
                and item["y"] <= my <= item["y"] + item["height"]
            ),
            None,
        )
        if zone:
            return zone
    return zones[0]


def draw_tk_focus_overlay(
    canvas: tk.Canvas,
    project: dict[str, Any],
    zoom: float,
    mode: str,
    active_layer: str,
    selected_ids: set[str],
    mouse_grid: tuple[float, float] | None,
) -> None:
    if mode == "Off":
        return
    settings = project["settings"]
    c = settings["cellSize"] * zoom
    color = settings.get("selectionColor", SELECT)
    if mode == "Active layer":
        for obj in project.get("objects", []):
            if obj.get("layer") != active_layer or not should_render_object(
                project, obj, for_export=False
            ):
                continue
            draw_tk_bounds(canvas, settings, bounds(obj), zoom, dash=(8, 3))
        label = f"Focus: {active_layer}"
    else:
        zone = active_focus_zone(project, selected_ids, mouse_grid)
        if not zone:
            return
        x = zone["x"] * c
        y = zone["y"] * c
        w = zone["width"] * c
        h = zone["height"] * c
        color = zone.get("color") or color
        canvas.create_rectangle(
            x,
            y,
            x + w,
            y + h,
            fill=color,
            stipple="gray12",
            outline=color,
            width=max(3, int(c * 0.12)),
        )
        label = f"Focus: {zone.get('name', 'Zone')}"
    view_left = canvas.canvasx(0)
    view_top = canvas.canvasy(0)
    text_id = canvas.create_text(
        view_left + 12,
        view_top + 12,
        text=label,
        anchor="nw",
        fill="#17384a",
        font=("Segoe UI", 10, "bold"),
    )
    box = canvas.bbox(text_id)
    if box:
        rect_id = canvas.create_rectangle(
            box[0] - 6,
            box[1] - 3,
            box[2] + 6,
            box[3] + 3,
            fill="#f9fcfd",
            outline=color,
        )
        canvas.tag_raise(text_id, rect_id)


def draw_tk_measure_overlay(
    canvas: tk.Canvas,
    settings: dict[str, Any],
    points: list[tuple[float, float]],
    preview: tuple[float, float] | None,
    zoom: float,
) -> None:
    live_points = list(points)
    if preview is not None and (
        not live_points
        or math.hypot(live_points[-1][0] - preview[0], live_points[-1][1] - preview[1])
        > 0.000001
    ):
        live_points.append(preview)
    if not live_points:
        return
    c = settings["cellSize"] * zoom
    color = settings.get("selectionColor", SELECT)
    px_points = [(x * c, y * c) for x, y in live_points]
    if len(px_points) >= 2:
        canvas.create_line(
            flatten_points(px_points),
            fill=color,
            width=max(2, int(c * 0.08)),
            dash=(5, 3),
        )
    if len(px_points) >= 3:
        canvas.create_polygon(
            flatten_points(px_points),
            outline=color,
            fill="",
            width=max(1, int(c * 0.04)),
            dash=(3, 3),
        )
    for index, (x, y) in enumerate(px_points, start=1):
        r = max(4, c * 0.14)
        canvas.create_oval(x - r, y - r, x + r, y + r, fill=color, outline="#17384a")
        canvas.create_text(
            x + r * 1.5,
            y - r * 1.5,
            text=str(index),
            fill="#17384a",
            font=("Segoe UI", max(7, int(c * 0.34)), "bold"),
        )


def nice_ruler_cells(value: float) -> float:
    value = max(1.0, value)
    magnitude = 10 ** math.floor(math.log10(value))
    for step in (1, 2, 5, 10):
        candidate = step * magnitude
        if candidate >= value:
            return candidate
    return 10 * magnitude


def draw_tk_ruler_overlay(
    canvas: tk.Canvas,
    project: dict[str, Any],
    zoom: float,
    mouse_grid: tuple[float, float] | None,
    measure_points: list[tuple[float, float]],
) -> None:
    settings = project["settings"]
    if not settings.get("showRuler", True):
        return
    c = settings["cellSize"] * zoom
    view_left = canvas.canvasx(0)
    view_bottom = canvas.canvasy(max(1, canvas.winfo_height()))
    pad = 10
    bar_cells = nice_ruler_cells(120 / max(1, c))
    bar_px = bar_cells * c
    x = view_left + pad
    y = view_bottom - 34
    bg = soften_color(settings.get("floorColor", WHITE), 0.1)
    ink = settings.get("gridColor", BLUE)
    text = f"{format_measure_value(bar_cells)} cells / {real_distance_label(bar_cells, settings)}"
    if mouse_grid:
        text += f" | {mouse_grid[0]:.2f},{mouse_grid[1]:.2f}"
    if len(measure_points) >= 2:
        text += " | " + measurement_summary(measure_points, settings).replace(
            "measure | ", ""
        )
    text_width = max(bar_px, 120, len(text) * 7)
    canvas.create_rectangle(
        x - 6, y - 18, x + text_width + 16, y + 12, fill=bg, outline=ink
    )
    canvas.create_line(x, y, x + bar_px, y, fill=ink, width=3)
    canvas.create_line(x, y - 5, x, y + 5, fill=ink, width=2)
    canvas.create_line(x + bar_px, y - 5, x + bar_px, y + 5, fill=ink, width=2)
    canvas.create_text(
        x, y - 12, text=text, anchor="w", fill=ink, font=("Segoe UI", 9, "bold")
    )


def draw_tk_room_status(
    canvas: tk.Canvas,
    settings: dict[str, Any],
    rooms: list[dict[str, Any]],
    zoom: float,
) -> None:
    c = settings["cellSize"] * zoom
    for room in rooms:
        color = ROOM_STATUS_COLORS.get(str(room.get("roomStatus") or ""), "")
        if not color:
            continue
        x, y, w, h = bounds(room)
        width = max(2, int(c * 0.12))
        if is_polygon_room(room):
            points = floor_polygon_points(room, c)
            canvas.create_line(
                flatten_points(points + [points[0]]),
                fill=color,
                width=width,
                smooth=False,
            )
        elif has_floor_rotation(room) and room.get("type") in {"room", "round"}:
            inset = width / c
            local = {
                **room,
                "x": float(room.get("x", 0)) + inset,
                "y": float(room.get("y", 0)) + inset,
                "width": max(0.01, float(room.get("width", 1)) - inset * 2),
                "height": max(0.01, float(room.get("height", 1)) - inset * 2),
            }
            points = floor_polygon_points(local, c)
            canvas.create_line(
                flatten_points(points + [points[0]]),
                fill=color,
                width=width,
                smooth=room.get("type") == "round",
            )
        else:
            canvas.create_rectangle(
                x * c + width,
                y * c + width,
                (x + w) * c - width,
                (y + h) * c - width,
                outline=color,
                width=width,
            )


def draw_tk_bounds(
    canvas: tk.Canvas,
    settings: dict[str, Any],
    box: tuple[float, float, float, float],
    zoom: float,
    dash: tuple[int, int] = (6, 4),
) -> None:
    x, y, w, h = box
    c = settings["cellSize"] * zoom
    canvas.create_rectangle(
        x * c - 4,
        y * c - 4,
        (x + w) * c + 4,
        (y + h) * c + 4,
        outline=settings.get("selectionColor", SELECT),
        width=2,
        dash=dash,
    )


def draw_tk_selection(
    canvas: tk.Canvas,
    settings: dict[str, Any],
    obj: dict[str, Any],
    zoom: float,
    show_handles: bool,
    multi_select: bool = False,
) -> None:
    c = settings["cellSize"] * zoom
    selection_color = "#5aa7d6" if multi_select else settings.get("selectionColor", SELECT)
    if is_polygon_room(obj):
        points = floor_polygon_points(obj, c)
        canvas.create_line(
            flatten_points(points + [points[0]]),
            fill=selection_color,
            width=2,
            dash=(3, 2) if multi_select else (6, 4),
        )
    elif obj.get("type") in RECTLIKE_TYPES and has_floor_rotation(obj):
        points = floor_polygon_points(obj, c)
        canvas.create_line(
            flatten_points(points + [points[0]]),
            fill=selection_color,
            width=2,
            dash=(3, 2) if multi_select else (6, 4),
        )
    else:
        draw_tk_bounds(
            canvas,
            {**settings, "selectionColor": selection_color},
            bounds(obj),
            zoom,
            dash=(3, 2) if multi_select else (6, 4),
        )
    if not show_handles:
        return
    size = max(6, min(10, int(HANDLE_PIXEL_SIZE + (1.0 - min(1.0, zoom)) * 3)))
    scale_color = "#f9fcfd"
    rotate_color = "#1f7fbd"
    point_color = "#1f7fbd"
    insert_color = "#54a66a"
    link_color = "#c7465c"
    handle_outline = "#0e3f63"
    for name, hx, hy in selection_handles(obj):
        px, py = hx * c, hy * c
        if name == "rotate":
            if obj.get("type") in RECTLIKE_TYPES:
                anchor_x, anchor_y = rectlike_center(obj)
            else:
                anchor_x, anchor_y = obj["x"], obj["y"]
            canvas.create_line(
                anchor_x * c,
                anchor_y * c,
                px,
                py,
                fill=rotate_color,
                width=2,
                dash=(2, 2),
            )
            canvas.create_oval(
                px - size / 2,
                py - size / 2,
                px + size / 2,
                py + size / 2,
                fill=rotate_color,
                outline=handle_outline,
                width=2,
            )
        elif name.startswith("insert:"):
            half = size / 2
            canvas.create_polygon(
                px,
                py - half,
                px + half,
                py,
                px,
                py + half,
                px - half,
                py,
                fill=insert_color,
                outline=handle_outline,
            )
            canvas.create_text(
                px,
                py,
                text="+",
                fill=handle_outline,
                font=("Segoe UI", max(6, int(size)), "bold"),
            )
        elif name.startswith("point:"):
            half = size / 2
            canvas.create_polygon(
                px,
                py - half,
                px + half,
                py + half,
                px - half,
                py + half,
                fill=point_color,
                outline=handle_outline,
                width=2,
            )
        elif name in {"start", "end"}:
            half = size / 2
            canvas.create_oval(
                px - half,
                py - half,
                px + half,
                py + half,
                fill=link_color,
                outline=handle_outline,
                width=2,
            )
            canvas.create_text(
                px,
                py,
                text="•",
                fill="#ffffff",
                font=("Segoe UI", max(7, int(size)), "bold"),
            )
        elif name == "scale":
            half = size / 2
            canvas.create_rectangle(
                px - half,
                py - half,
                px + half,
                py + half,
                fill=scale_color,
                outline=selection_color,
                width=2,
            )
            canvas.create_line(
                px - half + 2,
                py + half - 2,
                px + half - 2,
                py - half + 2,
                fill=selection_color,
                width=2,
            )
        else:
            canvas.create_rectangle(
                px - size / 2,
                py - size / 2,
                px + size / 2,
                py + size / 2,
                fill=scale_color,
                outline=selection_color,
                width=2,
            )


def draw_tk_object(
    canvas: tk.Canvas,
    project: dict[str, Any],
    settings: dict[str, Any],
    obj: dict[str, Any],
    zoom: float,
) -> None:
    if obj["type"] in RECTLIKE_TYPES:
        draw_tk_rectlike(canvas, settings, obj, zoom)
    elif obj["type"] == "diagonal_corridor":
        draw_tk_diagonal_corridor(canvas, settings, obj, zoom)
    elif obj["type"] == "symbol":
        c = settings["cellSize"] * zoom
        if is_custom_symbol(project, obj["kind"]):
            draw_tk_custom_symbol(canvas, project, obj, c, settings)
        else:
            draw_tk_builtin_symbol_rotated(canvas, project, obj, c, settings)
        draw_tk_rotation_indicator(canvas, obj, c, symbol_ink(settings, obj))
    elif obj["type"] == "text":
        c = settings["cellSize"] * zoom
        draw_tk_text(canvas, settings, obj, c)
    elif obj["type"] == "shape":
        draw_tk_shape(canvas, settings, obj, zoom)
    elif obj["type"] == "legend":
        draw_tk_legend_object(canvas, project, obj, zoom)


def draw_tk_shape(
    canvas: tk.Canvas,
    settings: dict[str, Any],
    obj: dict[str, Any],
    zoom: float,
    dash: tuple[int, int] | None = None,
) -> None:
    c = settings["cellSize"] * zoom
    opacity = shape_opacity(obj)
    ink = blend_color(
        obj.get("strokeColor") or settings["gridColor"],
        settings.get("backgroundColor", WHITE),
        opacity,
    )
    fill = obj.get("fillColor") or ""
    if fill:
        fill = blend_color(fill, settings.get("backgroundColor", WHITE), opacity)
    width = max(1, int(float(obj.get("lineWidth", 0.12)) * c))
    options = {"outline": ink, "width": width}
    dash = dash or tk_shape_dash(obj)
    if dash:
        options["dash"] = dash
    kind = obj.get("kind")
    if kind == "line":
        line_options: dict[str, Any] = {
            "fill": ink,
            "width": width,
            "capstyle": "round",
            "smooth": bool(obj.get("curve", False)),
        }
        if dash:
            line_options["dash"] = dash
        arrow = tk_arrow_value(obj)
        if arrow:
            line_options["arrow"] = arrow
            line_options["arrowshape"] = (
                max(8, width * 5),
                max(10, width * 6),
                max(3, width * 2),
            )
        start = (obj["x"] * c, obj["y"] * c)
        end = (obj["x2"] * c, obj["y2"] * c)
        if obj.get("curve", False):
            control = curved_line_control(start, end)
            canvas.create_line(flatten_points([start, control, end]), **line_options)
        else:
            canvas.create_line(start[0], start[1], end[0], end[1], **line_options)
        return
    x, y = obj["x"] * c, obj["y"] * c
    w, h = obj["width"] * c, obj["height"] * c
    if kind == "circle":
        canvas.create_oval(x, y, x + w, y + h, fill=fill, **options)
    elif kind == "polygon":
        points = shape_polygon_points(obj, c)
        if obj.get("_open") or len(points) < 3:
            if len(points) >= 2:
                canvas.create_line(
                    flatten_points(points),
                    fill=ink,
                    width=width,
                    dash=dash,
                    smooth=bool(obj.get("curve", False)),
                )
            if points:
                fx, fy = points[0]
                radius = max(4, width + 3)
                canvas.create_oval(
                    fx - radius,
                    fy - radius,
                    fx + radius,
                    fy + radius,
                    outline=ink,
                    width=max(1, width),
                    dash=dash,
                )
            return
        if obj.get("curve", False):
            options["smooth"] = True
        canvas.create_polygon(flatten_points(points), fill=fill, **options)
    else:
        canvas.create_rectangle(x, y, x + w, y + h, fill=fill, **options)


def draw_tk_rotation_indicator(
    canvas: tk.Canvas, obj: dict[str, Any], cell: float, ink: str
) -> None:
    rotation = float(obj.get("rotation", 0)) % 360
    if not rotation:
        return
    size = float(obj.get("size", 1)) * cell * 0.45
    angle = math.radians(rotation - 90)
    x, y = obj["x"] * cell, obj["y"] * cell
    canvas.create_line(
        x,
        y,
        x + math.cos(angle) * size,
        y + math.sin(angle) * size,
        fill=ink,
        width=max(1, int(cell * 0.08)),
        arrow="last",
        )


def tk_builtin_symbol_photo_image(
    project: dict[str, Any],
    obj: dict[str, Any],
    cell: float,
    settings: dict[str, Any],
):
    if Image is None or ImageDraw is None or ImageTk is None:
        return None
    kind = effective_symbol_kind(project, obj)
    rotation = float(obj.get("rotation", 0)) % 360
    size_px = max(8, int(obj.get("size", 1) * cell))
    side = max(16, int(size_px * 2.7))
    scale = max(1, int(cell / settings["cellSize"]))
    key = stable_cache_hash(
        {
            "type": "builtin",
            "kind": kind,
            "size": size_px,
            "side": side,
            "scale": scale,
            "rotation": round(rotation, 2),
            "shadow": bool(obj.get("shadow")),
            "outline": bool(obj.get("outline")),
            "ink": symbol_ink(settings, obj),
            "outlineColor": symbol_outline_color(settings, obj),
            "shadowColor": symbol_shadow_color(settings, obj),
            "floorColor": settings["floorColor"],
            "opacity": round(symbol_opacity(obj), 4),
        }
    )
    cached = cache_get(_TK_SYMBOL_PHOTO_CACHE, key)
    if cached is not None:
        return cached
    image = Image.new("RGBA", (side, side), (0, 0, 0, 0))
    draw = ImageDraw.Draw(image)
    center = side / 2
    if obj.get("shadow"):
        offset = max(1, int(size_px * 0.08))
        draw_pillow_symbol(
            draw,
            kind,
            center + offset,
            center + offset,
            size_px,
            symbol_shadow_color(settings, obj),
            settings["floorColor"],
            scale,
        )
    if obj.get("outline"):
        draw_pillow_symbol(
            draw,
            kind,
            center,
            center,
            size_px * 1.12,
            symbol_outline_color(settings, obj),
            settings["floorColor"],
            scale,
        )
    draw_pillow_symbol(
        draw,
        kind,
        center,
        center,
        size_px,
        symbol_ink(settings, obj),
        settings["floorColor"],
        scale,
    )
    if abs(rotation) >= 0.01:
        image = image.rotate(-rotation, resample=Image.Resampling.BICUBIC, expand=True)
    image = image_with_opacity(image, symbol_opacity(obj))
    photo = ImageTk.PhotoImage(image)
    return cache_put(_TK_SYMBOL_PHOTO_CACHE, key, photo, TK_SYMBOL_IMAGE_CACHE_LIMIT)


def draw_tk_text(
    canvas: tk.Canvas, settings: dict[str, Any], obj: dict[str, Any], cell: float
) -> None:
    align = obj.get("align", "center")
    anchor = {"left": "nw", "center": "n", "right": "ne"}.get(align, "n")
    x = obj["x"] * cell
    y = obj["y"] * cell
    width = obj.get("width", 0) * cell if obj.get("width", 0) else 0
    font = (
        obj.get("font") or settings.get("defaultTextFont", "Arial"),
        max(7, int(obj.get("size", 1) * cell)),
        "bold",
    )
    fill = obj.get("color") or settings.get("textColor", settings["gridColor"])
    if obj.get("textRole") == "note" or not obj.get("export", True):
        fill = soften_color(fill, 0.25)
        canvas.create_rectangle(
            x - 3,
            y - 3,
            x + max(width, cell * 4),
            y + cell * 2.2,
            fill=soften_color(settings["floorColor"], 0.15),
            outline=fill,
            dash=(3, 2),
        )
        anchor = "nw"
    options = {
        "text": obj.get("text", ""),
        "anchor": anchor,
        "fill": fill,
        "font": font,
        "justify": align if align in {"left", "center", "right"} else "center",
    }
    if width:
        options["width"] = width
    rotation = float(obj.get("rotation", 0)) % 360
    if rotation:
        options["angle"] = -rotation
    canvas.create_text(x, y, **options)


def styled_custom_symbol_image(image, obj: dict[str, Any], settings: dict[str, Any]):
    if Image is None or ImageDraw is None:
        return image
    key = stable_cache_hash(
        {
            "image": (id(image), image.size, image.mode),
            "shadow": bool(obj.get("shadow")),
            "outline": bool(obj.get("outline")),
            "outlineColor": symbol_outline_color(settings, obj),
            "opacity": round(symbol_opacity(obj), 4),
            "floorColor": settings.get("floorColor", WHITE),
        }
    )
    cached = cache_get(_STYLED_CUSTOM_SYMBOL_IMAGE_CACHE, key)
    if cached is not None:
        return image_copy_or_none(cached)
    padding = max(2, int(max(image.width, image.height) * 0.14))
    side_w = image.width + padding * 2
    side_h = image.height + padding * 2
    result = Image.new("RGBA", (side_w, side_h), (0, 0, 0, 0))
    left = padding
    top = padding
    if obj.get("shadow"):
        shadow = image_shadow(image, 0.35)
        offset = max(1, int(max(image.width, image.height) * 0.08))
        result.alpha_composite(shadow, (left + offset, top + offset))
    if obj.get("outline"):
        draw = ImageDraw.Draw(result)
        draw.rectangle(
            (left - 1, top - 1, left + image.width + 1, top + image.height + 1),
            outline=symbol_outline_color(settings, obj),
            width=max(1, int(max(image.width, image.height) * 0.05)),
        )
    result.alpha_composite(image_with_opacity(image, symbol_opacity(obj)), (left, top))
    cache_put(
        _STYLED_CUSTOM_SYMBOL_IMAGE_CACHE,
        key,
        result.copy(),
        TK_SYMBOL_IMAGE_CACHE_LIMIT,
    )
    return result


def tk_custom_symbol_photo_image(
    project: dict[str, Any],
    obj: dict[str, Any],
    cell: float,
    settings: dict[str, Any],
):
    if ImageTk is None:
        return None
    size_px = max(8, int(obj.get("size", 1) * cell))
    variant = str(obj.get("variant", ""))
    key = stable_cache_hash(
        {
            "type": "custom",
            "source": custom_symbol_source_cache_token(project, obj["kind"], variant),
            "kind": obj["kind"],
            "size": size_px,
            "rotation": round(float(obj.get("rotation", 0)), 2),
            "variant": variant,
            "shadow": bool(obj.get("shadow")),
            "outline": bool(obj.get("outline")),
            "outlineColor": symbol_outline_color(settings, obj),
            "opacity": round(symbol_opacity(obj), 4),
            "floorColor": settings.get("floorColor", WHITE),
        }
    )
    cached = cache_get(_TK_SYMBOL_PHOTO_CACHE, key)
    if cached is not None:
        return cached
    image = load_custom_symbol_image(
        project,
        obj["kind"],
        size_px,
        float(obj.get("rotation", 0)),
        variant,
    )
    if image is None:
        return None
    photo = ImageTk.PhotoImage(styled_custom_symbol_image(image, obj, settings))
    return cache_put(_TK_SYMBOL_PHOTO_CACHE, key, photo, TK_SYMBOL_IMAGE_CACHE_LIMIT)


def draw_tk_custom_symbol(
    canvas: tk.Canvas,
    project: dict[str, Any],
    obj: dict[str, Any],
    cell: float,
    settings: dict[str, Any],
) -> None:
    x = obj["x"] * cell
    y = obj["y"] * cell
    photo = tk_custom_symbol_photo_image(project, obj, cell, settings)
    if photo is None:
        label = symbol_label(project, obj["kind"])[:2].upper()
        ink = symbol_ink(settings, obj)
        if obj.get("shadow"):
            canvas.create_rectangle(
                x - cell * 0.45 + cell * 0.08,
                y - cell * 0.45 + cell * 0.08,
                x + cell * 0.45 + cell * 0.08,
                y + cell * 0.45 + cell * 0.08,
                fill="#000000",
                outline="",
                stipple="gray50",
            )
        if obj.get("outline"):
            canvas.create_rectangle(
                x - cell * 0.5,
                y - cell * 0.5,
                x + cell * 0.5,
                y + cell * 0.5,
                fill="",
                outline=symbol_outline_color(settings, obj),
                width=max(1, int(cell * 0.08)),
            )
        canvas.create_rectangle(
            x - cell * 0.45,
            y - cell * 0.45,
            x + cell * 0.45,
            y + cell * 0.45,
            fill=settings["floorColor"],
            outline=ink,
            width=2,
        )
        canvas.create_text(
            x, y, text=label, fill=ink, font=("Arial", max(8, int(cell * 0.6)), "bold")
        )
        return
    canvas.create_image(x, y, image=photo)
    refs = getattr(canvas, "_image_refs", [])
    refs.append(photo)
    canvas._image_refs = refs


def draw_tk_builtin_symbol_rotated(
    canvas: tk.Canvas,
    project: dict[str, Any],
    obj: dict[str, Any],
    cell: float,
    settings: dict[str, Any],
    ) -> None:
    x, y, size = obj["x"] * cell, obj["y"] * cell, obj.get("size", 1) * cell
    kind = effective_symbol_kind(project, obj)
    rotation = float(obj.get("rotation", 0)) % 360
    ink = blend_color(
        symbol_ink(settings, obj),
        settings.get("backgroundColor", WHITE),
        symbol_opacity(obj),
    )
    if abs(rotation) < 0.01 or Image is None or ImageDraw is None:
        if obj.get("shadow"):
            draw_tk_symbol(
                canvas,
                kind,
                x + cell * 0.08,
                y + cell * 0.08,
                size,
                symbol_shadow_color(settings, obj),
                settings["floorColor"],
            )
        if obj.get("outline"):
            draw_tk_symbol(
                canvas,
                kind,
                x,
                y,
                size * 1.12,
                symbol_outline_color(settings, obj),
                settings["floorColor"],
            )
        draw_tk_symbol(
            canvas,
            kind,
            x,
            y,
            size,
            ink,
            settings["floorColor"],
        )
        return
    photo = tk_builtin_symbol_photo_image(project, obj, cell, settings)
    if photo is None:
        return
    canvas.create_image(obj["x"] * cell, obj["y"] * cell, image=photo)
    refs = getattr(canvas, "_image_refs", [])
    refs.append(photo)
    canvas._image_refs = refs


def draw_tk_legend_object(
    canvas: tk.Canvas, project: dict[str, Any], obj: dict[str, Any], zoom: float
) -> None:
    settings = project["settings"]
    c = settings["cellSize"] * zoom
    layout = legend_layout(project, obj)
    x, y = obj["x"] * c, obj["y"] * c
    width, height = layout.width * c, layout.height * c
    ink = settings.get("legendColor", settings["gridColor"])
    canvas.create_rectangle(
        x, y, x + width, y + height, fill=settings["floorColor"], outline=ink, width=2
    )
    title_size = max(10, int(c * layout.scale * 1.1))
    canvas.create_text(
        x + c * 0.65,
        y + c * 0.8,
        text="LEGEND",
        anchor="w",
        fill=ink,
        font=("Arial", title_size, "bold"),
    )
    for index, (kind, label) in enumerate(layout.entries):
        ex, ey = legend_entry_position(layout, x, y, c, index)
        if kind == "cell":
            canvas.create_rectangle(
                ex,
                ey - c * 0.35,
                ex + c * 0.7,
                ey + c * 0.35,
                fill=settings["floorColor"],
                outline=ink,
            )
        elif kind == "manual":
            canvas.create_text(
                ex + c * 0.2,
                ey,
                text="•",
                anchor="w",
                fill=ink,
                font=("Arial", max(7, int(c * 0.7)), "bold"),
            )
        elif is_custom_symbol(project, kind):
            draw_tk_custom_symbol(
                canvas,
                project,
                {
                    "kind": kind,
                    "x": (ex + c * 0.35) / c,
                    "y": ey / c,
                    "size": 0.75,
                    "rotation": 0,
                },
                c,
                settings,
            )
        else:
            draw_tk_symbol(
                canvas, kind, ex + c * 0.35, ey, c * 0.7, ink, settings["floorColor"]
            )
        canvas.create_text(
            ex + c * 1.1,
            ey,
            text=label,
            anchor="w",
            fill=ink,
            font=("Arial", max(7, int(c * 0.55 * layout.scale)), "bold"),
        )


def draw_tk_floor_objects(
    canvas: tk.Canvas,
    settings: dict[str, Any],
    objects: list[dict[str, Any]],
    zoom: float,
) -> None:
    if not objects:
        return
    if settings.get("showFloorOutlines", True):
        for obj in objects:
            draw_tk_floor_outline(canvas, settings, obj, zoom)
    for obj in objects:
        draw_tk_floor_fill(canvas, settings, obj, zoom)
    c = settings["cellSize"] * zoom
    for x1, y1, x2, y2, wall in shared_exact_floor_edges(objects):
        canvas.create_line(
            x1 * c,
            y1 * c,
            x2 * c,
            y2 * c,
            fill=settings["floorColor"],
            width=max(2, int(c * wall)),
        )
    for obj in objects:
        draw_tk_floor_grid(canvas, settings, obj, zoom)
    if not settings.get("showFloorOutlines", True):
        for obj in objects:
            draw_tk_floor_boundary_mask(canvas, settings, obj, zoom)


def draw_tk_floor_outline(
    canvas: tk.Canvas, settings: dict[str, Any], obj: dict[str, Any], zoom: float
) -> None:
    c = settings["cellSize"] * zoom
    ink = settings.get("floorOutlineColor", BLUE)
    wall = max(1.0, c * max(0.02, coerce_float(obj.get("wallThickness"), 0.16)) / 2)
    obj_type = obj.get("type")
    if obj_type == "diagonal_corridor":
        x1, y1 = obj["x"] * c, obj["y"] * c
        x2, y2 = obj["x2"] * c, obj["y2"] * c
        thickness = max(3, int(obj.get("width", 1) * c))
        outline = thickness + max(
            2, int(c * max(0.02, coerce_float(obj.get("wallThickness"), 0.16)))
        )
        canvas.create_polygon(
            flatten_points(corridor_polygon_points(x1, y1, x2, y2, outline)),
            fill=ink,
            outline="",
        )
        return
    if is_polygon_room(obj):
        points = floor_polygon_points(obj, c)
        canvas.create_line(
            flatten_points(points + [points[0]]),
            fill=ink,
            width=max(2, int(wall * 2)),
            smooth=False,
        )
        return
    x, y = obj["x"] * c, obj["y"] * c
    w, h = obj["width"] * c, obj["height"] * c
    if has_floor_rotation(obj) and obj_type in {"room", "corridor", "round"}:
        canvas.create_polygon(
            flatten_points(expanded_floor_polygon_points(obj, c, wall)),
            fill=ink,
            outline="",
            smooth=floor_boundary_is_smooth(obj),
        )
    elif obj_type == "round":
        canvas.create_oval(
            x - wall, y - wall, x + w + wall, y + h + wall, fill=ink, outline=""
        )
    elif obj_type in {"cave", "cave_corridor"}:
        points = floor_polygon_points(obj, c)
        canvas.create_line(
            flatten_points(points + [points[0]]),
            fill=ink,
            width=max(2, int(wall * 2)),
            smooth=floor_boundary_is_smooth(obj),
        )
    else:
        canvas.create_rectangle(
            x - wall, y - wall, x + w + wall, y + h + wall, fill=ink, outline=""
        )


def draw_tk_floor_fill(
    canvas: tk.Canvas, settings: dict[str, Any], obj: dict[str, Any], zoom: float
) -> None:
    c = settings["cellSize"] * zoom
    floor = settings["floorColor"]
    mask_boundary = not settings.get("showFloorOutlines", True)
    outline = floor if mask_boundary else ""
    width = max(2, int(zoom * 2)) if mask_boundary else 1
    obj_type = obj.get("type")
    if obj_type == "diagonal_corridor":
        canvas.create_polygon(
            flatten_points(floor_polygon_points(obj, c)),
            fill=floor,
            outline=outline,
            width=width,
        )
        return
    if is_polygon_room(obj):
        canvas.create_polygon(
            flatten_points(floor_polygon_points(obj, c)),
            fill=floor,
            outline=outline,
            width=width,
            smooth=False,
        )
        draw_tk_texture_fill(canvas, settings, obj, zoom)
        return
    x, y = obj["x"] * c, obj["y"] * c
    w, h = obj["width"] * c, obj["height"] * c
    if has_floor_rotation(obj):
        canvas.create_polygon(
            flatten_points(floor_polygon_points(obj, c)),
            fill=floor,
            outline=outline,
            width=width,
            smooth=floor_boundary_is_smooth(obj),
        )
    elif obj_type == "round":
        canvas.create_oval(
            x, y, x + w, y + h, fill=floor, outline=outline, width=width
        )
    elif obj_type in {"cave", "cave_corridor"}:
        canvas.create_polygon(
            flatten_points(floor_polygon_points(obj, c)),
            fill=floor,
            outline=outline,
            width=width,
            smooth=floor_boundary_is_smooth(obj),
        )
    else:
        canvas.create_rectangle(
            x, y, x + w, y + h, fill=floor, outline=outline, width=width
        )
    draw_tk_texture_fill(canvas, settings, obj, zoom)


def draw_tk_floor_boundary_mask(
    canvas: tk.Canvas, settings: dict[str, Any], obj: dict[str, Any], zoom: float
) -> None:
    c = settings["cellSize"] * zoom
    floor = settings["floorColor"]
    width = max(2, int(zoom * 2))
    obj_type = obj.get("type")
    if obj_type == "diagonal_corridor":
        canvas.create_polygon(
            flatten_points(floor_polygon_points(obj, c)),
            fill="",
            outline=floor,
            width=width,
        )
        return
    if is_polygon_room(obj):
        points = floor_polygon_points(obj, c)
        canvas.create_line(
            flatten_points(points + [points[0]]),
            fill=floor,
            width=width,
            smooth=False,
        )
        return
    x, y = obj["x"] * c, obj["y"] * c
    w, h = obj["width"] * c, obj["height"] * c
    if has_floor_rotation(obj):
        points = floor_polygon_points(obj, c)
        canvas.create_line(
            flatten_points(points + [points[0]]),
            fill=floor,
            width=width,
            smooth=floor_boundary_is_smooth(obj),
        )
    elif obj_type == "round":
        canvas.create_oval(x, y, x + w, y + h, fill="", outline=floor, width=width)
    elif obj_type in {"cave", "cave_corridor"}:
        points = floor_polygon_points(obj, c)
        canvas.create_line(
            flatten_points(points + [points[0]]),
            fill=floor,
            width=width,
            smooth=floor_boundary_is_smooth(obj),
        )
    else:
        canvas.create_rectangle(
            x, y, x + w, y + h, fill="", outline=floor, width=width
        )


def draw_tk_floor_grid(
    canvas: tk.Canvas, settings: dict[str, Any], obj: dict[str, Any], zoom: float
) -> None:
    c = settings["cellSize"] * zoom
    for gx1, gy1, gx2, gy2 in floor_grid_segments(
        obj,
        c,
        include_boundary=settings.get("showFloorOutlines", True),
    ):
        canvas.create_line(gx1, gy1, gx2, gy2, fill=settings["gridColor"])


def texture_fill_color(settings: dict[str, Any], texture: str) -> str:
    colors = {
        "stone": soften_color(settings["gridColor"], 0.25),
        "earth": "#8f6f45",
        "water": "#4aa3c7",
        "wood": "#9a6a3a",
        "lava": "#d9532f",
    }
    return colors.get(texture, "")


def draw_tk_texture_fill(
    canvas: tk.Canvas, settings: dict[str, Any], obj: dict[str, Any], zoom: float
) -> None:
    if has_floor_rotation(obj):
        return
    texture = str(obj.get("textureFill") or "")
    color = texture_fill_color(settings, texture)
    if not color:
        return
    c = settings["cellSize"] * zoom
    x, y, w, h = bounds(obj)
    left, top, bottom = x * c, y * c, (y + h) * c
    step = max(6, int(c * 0.75))
    for offset in range(-int(h * c), int(w * c) + step, step):
        canvas.create_line(
            left + offset,
            top,
            left + offset + h * c,
            bottom,
            fill=color,
            stipple="gray50",
        )


def draw_tk_rectlike(
    canvas: tk.Canvas,
    settings: dict[str, Any],
    obj: dict[str, Any],
    zoom: float,
    stipple: str = "",
) -> None:
    c = settings["cellSize"] * zoom
    x, y, w, h = obj["x"] * c, obj["y"] * c, obj["width"] * c, obj["height"] * c
    obj_type = obj.get("type", obj.get("kind"))
    if obj_type == "round":
        canvas.create_oval(
            x,
            y,
            x + w,
            y + h,
            fill=settings["floorColor"],
            outline=settings["gridColor"],
            width=2,
            stipple=stipple,
        )
    elif is_polygon_room(obj):
        points = floor_polygon_points(obj, c)
        canvas.create_polygon(
            flatten_points(points),
            fill=settings["floorColor"],
            outline=settings["gridColor"],
            width=2,
            smooth=False,
            stipple=stipple,
        )
        for gx1, gy1, gx2, gy2 in floor_grid_segments(obj, c):
            canvas.create_line(gx1, gy1, gx2, gy2, fill=settings["gridColor"])
        return
    elif obj_type in {"cave", "cave_corridor"}:
        points = floor_polygon_points(obj, c)
        canvas.create_polygon(
            points,
            fill=settings["floorColor"],
            outline=settings["gridColor"],
            width=2,
            smooth=floor_boundary_is_smooth(obj),
            stipple=stipple,
        )
    else:
        canvas.create_rectangle(
            x,
            y,
            x + w,
            y + h,
            fill=settings["floorColor"],
            outline=settings["gridColor"],
            stipple=stipple,
        )
    for gx in range(int(obj["width"]) + 1):
        canvas.create_line(x + gx * c, y, x + gx * c, y + h, fill=settings["gridColor"])
    for gy in range(int(obj["height"]) + 1):
        canvas.create_line(x, y + gy * c, x + w, y + gy * c, fill=settings["gridColor"])


def draw_tk_diagonal_corridor(
    canvas: tk.Canvas, settings: dict[str, Any], obj: dict[str, Any], zoom: float
) -> None:
    c = settings["cellSize"] * zoom
    x1, y1 = obj["x"] * c, obj["y"] * c
    x2, y2 = obj["x2"] * c, obj["y2"] * c
    thickness = max(3, int(obj.get("width", 1) * c))
    outline = thickness + max(
        2, int(c * max(0.02, coerce_float(obj.get("wallThickness"), 0.16)))
    )
    outline_polygon = corridor_polygon_points(x1, y1, x2, y2, outline)
    floor_polygon = corridor_polygon_points(x1, y1, x2, y2, thickness)
    canvas.create_polygon(
        flatten_points(outline_polygon), fill=settings["gridColor"], outline=""
    )
    canvas.create_polygon(
        flatten_points(floor_polygon), fill=settings["floorColor"], outline=""
    )
    for gx1, gy1, gx2, gy2 in orthogonal_grid_segments(floor_polygon, c):
        canvas.create_line(gx1, gy1, gx2, gy2, fill=settings["gridColor"])


def draw_tk_vector_symbol(
    canvas: tk.Canvas,
    kind: str,
    x: float,
    y: float,
    s: float,
    ink: str,
    floor: str,
    width: int,
) -> bool:
    ops = vector_symbol_ops(kind)
    if not ops:
        return False
    for op in ops:
        op_type = op[0]
        if op_type == "line":
            canvas.create_line(
                x + op[1] * s,
                y + op[2] * s,
                x + op[3] * s,
                y + op[4] * s,
                fill=ink,
                width=width,
            )
        elif op_type == "polyline":
            canvas.create_line(
                *flatten_points(vector_symbol_points(x, y, s, op[1])),
                fill=ink,
                smooth=False,
                width=width,
            )
        elif op_type == "polygon":
            canvas.create_polygon(
                *flatten_points(vector_symbol_points(x, y, s, op[1])),
                fill=vector_symbol_fill(op[2], ink, floor) or "",
                outline=ink,
                width=width,
            )
        elif op_type == "rect":
            canvas.create_rectangle(
                x + op[1] * s,
                y + op[2] * s,
                x + op[3] * s,
                y + op[4] * s,
                fill=vector_symbol_fill(op[5], ink, floor) or "",
                outline=ink,
                width=width,
            )
        elif op_type == "ellipse":
            canvas.create_oval(
                x + (op[1] - op[3]) * s,
                y + (op[2] - op[4]) * s,
                x + (op[1] + op[3]) * s,
                y + (op[2] + op[4]) * s,
                fill=vector_symbol_fill(op[5], ink, floor) or "",
                outline=ink,
                width=width,
            )
        elif op_type == "text":
            canvas.create_text(
                x + op[2] * s,
                y + op[3] * s,
                text=op[1],
                fill=ink,
                font=("Arial", max(7, int(s * op[4])), "bold"),
            )
    return True


def draw_tk_symbol(
    canvas: tk.Canvas, kind: str, x: float, y: float, size: float, ink: str, floor: str
) -> None:
    kind = normalize_symbol_kind(kind)
    s = size
    w = max(1, int(s * 0.12))
    if kind in DOOR_SYMBOLS:
        draw_tk_door(canvas, kind, x, y, s, ink, floor, w)
    elif kind in HAZARD_SYMBOLS:
        canvas.create_rectangle(
            x - s * 0.45, y - s * 0.45, x + s * 0.45, y + s * 0.45, outline=ink, width=w
        )
        if kind == "covered_pit":
            canvas.create_line(
                x - s * 0.32,
                y - s * 0.32,
                x + s * 0.32,
                y + s * 0.32,
                fill=ink,
                width=w,
            )
            canvas.create_line(
                x + s * 0.32,
                y - s * 0.32,
                x - s * 0.32,
                y + s * 0.32,
                fill=ink,
                width=w,
            )
        elif kind == "open_pit":
            canvas.create_rectangle(
                x - s * 0.25,
                y - s * 0.25,
                x + s * 0.25,
                y + s * 0.25,
                fill=ink,
                outline=ink,
            )
        else:
            letters = {
                "trap": "T",
                "trap_ceiling": "C",
                "trap_floor": "F",
                "secret_trap_door": "S",
            }
            label = letters.get(kind, symbol_icon(kind).strip()[:2])
            canvas.create_text(
                x,
                y,
                text=label,
                fill=ink,
                font=(
                    "Arial",
                    max(8, int(s * (0.62 if len(label) > 1 else 0.75))),
                    "bold",
                ),
            )
    elif kind in {"stairs", "stair_slide_trap", "natural_stairs"}:
        for i in range(7):
            offset = i * s * 0.14
            canvas.create_line(
                x - s * 0.48 + offset,
                y - s * 0.42,
                x - s * 0.26 + offset,
                y + s * 0.42,
                fill=ink,
                width=w,
            )
        if kind == "stair_slide_trap":
            canvas.create_line(
                x - s * 0.48,
                y + s * 0.45,
                x + s * 0.48,
                y + s * 0.45,
                fill=ink,
                width=w,
            )
        if kind == "natural_stairs":
            canvas.create_arc(
                x - s * 0.5,
                y - s * 0.45,
                x + s * 0.5,
                y + s * 0.4,
                start=0,
                extent=180,
                outline=ink,
                width=w,
            )
    elif kind == "spiral_stairs":
        for radius in (0.15, 0.3, 0.45):
            canvas.create_oval(
                x - s * radius,
                y - s * radius,
                x + s * radius,
                y + s * radius,
                outline=ink,
                width=w,
            )
        canvas.create_line(x, y, x + s * 0.45, y, fill=ink, width=w)
    elif kind == "ladder":
        canvas.create_line(
            x - s * 0.25, y - s * 0.45, x - s * 0.25, y + s * 0.45, fill=ink, width=w
        )
        canvas.create_line(
            x + s * 0.25, y - s * 0.45, x + s * 0.25, y + s * 0.45, fill=ink, width=w
        )
        for i in range(5):
            yy = y - s * 0.35 + i * s * 0.18
            canvas.create_line(x - s * 0.25, yy, x + s * 0.25, yy, fill=ink, width=w)
    elif kind == "slide":
        canvas.create_line(x - s * 0.45, y, x + s * 0.35, y, fill=ink, width=w)
        canvas.create_line(
            x + s * 0.18, y - s * 0.18, x + s * 0.38, y, fill=ink, width=w
        )
        canvas.create_line(
            x + s * 0.18, y + s * 0.18, x + s * 0.38, y, fill=ink, width=w
        )
    elif kind in {"pillar", "rock_column", "boulder", "boulder_cluster"}:
        if kind == "boulder_cluster":
            for ox, oy, radius in (
                (-0.18, 0.08, 0.22),
                (0.14, -0.1, 0.26),
                (0.28, 0.2, 0.16),
            ):
                canvas.create_oval(
                    x + s * ox - s * radius,
                    y + s * oy - s * radius,
                    x + s * ox + s * radius,
                    y + s * oy + s * radius,
                    fill=ink,
                    outline=ink,
                )
        else:
            rx = s * (0.36 if kind == "boulder" else 0.3)
            ry = s * (0.28 if kind == "boulder" else 0.3)
            canvas.create_oval(x - rx, y - ry, x + rx, y + ry, fill=ink, outline=ink)
        if kind == "rock_column":
            canvas.create_text(
                x, y, text="×", fill=floor, font=("Arial", max(7, int(s * 0.7)), "bold")
            )
    elif kind == "statue":
        canvas.create_oval(
            x - s * 0.45, y - s * 0.45, x + s * 0.45, y + s * 0.45, outline=ink, width=w
        )
        canvas.create_text(
            x, y, text="*", fill=ink, font=("Arial", max(8, int(s)), "bold")
        )
    elif kind in {"fountain", "well"}:
        canvas.create_oval(
            x - s * 0.42, y - s * 0.42, x + s * 0.42, y + s * 0.42, outline=ink, width=w
        )
        canvas.create_oval(
            x - s * 0.18, y - s * 0.18, x + s * 0.18, y + s * 0.18, outline=ink, width=w
        )
        if kind == "fountain":
            canvas.create_arc(
                x - s * 0.25,
                y - s * 0.35,
                x + s * 0.25,
                y + s * 0.15,
                start=200,
                extent=140,
                outline=ink,
                width=w,
            )
    elif kind in {"pool", "pool_lake", "stream", "curtain", "submerged_path"}:
        for i in range(3):
            yy = y - s * 0.25 + i * s * 0.25
            canvas.create_line(
                x - s * 0.42,
                yy,
                x - s * 0.15,
                yy + s * 0.08,
                x + s * 0.15,
                yy - s * 0.08,
                x + s * 0.42,
                yy,
                fill=ink,
                smooth=True,
                width=w,
            )
    elif kind in {"dais", "teleporter"}:
        canvas.create_rectangle(
            x - s * 0.42, y - s * 0.42, x + s * 0.42, y + s * 0.42, outline=ink, width=w
        )
        canvas.create_rectangle(
            x - s * 0.25, y - s * 0.25, x + s * 0.25, y + s * 0.25, outline=ink, width=w
        )
        if kind == "teleporter":
            for i in range(9):
                px = x - s * 0.25 + (i % 3) * s * 0.25
                py = y - s * 0.25 + (i // 3) * s * 0.25
                canvas.create_rectangle(
                    px, py, px + s * 0.08, py + s * 0.08, fill=ink, outline=ink
                )
    elif kind == "altar":
        canvas.create_rectangle(
            x - s * 0.2, y - s * 0.48, x + s * 0.2, y + s * 0.48, outline=ink, width=w
        )
        canvas.create_rectangle(
            x - s * 0.07,
            y - s * 0.22,
            x + s * 0.07,
            y - s * 0.08,
            fill=ink,
            outline=ink,
        )
        canvas.create_rectangle(
            x - s * 0.07,
            y + s * 0.12,
            x + s * 0.07,
            y + s * 0.26,
            fill=ink,
            outline=ink,
        )
    elif kind == "fireplace":
        canvas.create_rectangle(
            x - s * 0.38, y - s * 0.4, x + s * 0.38, y + s * 0.15, outline=ink, width=w
        )
        canvas.create_arc(
            x - s * 0.25,
            y - s * 0.15,
            x + s * 0.25,
            y + s * 0.45,
            start=0,
            extent=180,
            outline=ink,
            width=w,
        )
    elif kind == "table_chest":
        canvas.create_rectangle(
            x - s * 0.45, y - s * 0.2, x - s * 0.05, y + s * 0.2, outline=ink, width=w
        )
        canvas.create_rectangle(
            x + s * 0.08, y - s * 0.18, x + s * 0.42, y + s * 0.18, outline=ink, width=w
        )
        canvas.create_line(x + s * 0.08, y, x + s * 0.42, y, fill=ink, width=w)
    elif kind == "bed":
        canvas.create_rectangle(
            x - s * 0.42, y - s * 0.25, x + s * 0.42, y + s * 0.25, outline=ink, width=w
        )
        canvas.create_line(
            x - s * 0.18, y - s * 0.25, x - s * 0.18, y + s * 0.25, fill=ink, width=w
        )
    elif kind in {"railing", "illusory_wall", "rock_wall", "subterranean_passage"}:
        if kind == "railing":
            for i in range(5):
                canvas.create_oval(
                    x - s * 0.45 + i * s * 0.22,
                    y - s * 0.06,
                    x - s * 0.37 + i * s * 0.22,
                    y + s * 0.06,
                    fill=ink,
                    outline=ink,
                )
        elif kind == "illusory_wall":
            for i in range(4):
                canvas.create_line(
                    x - s * 0.45 + i * s * 0.24,
                    y,
                    x - s * 0.32 + i * s * 0.24,
                    y,
                    fill=ink,
                    width=w,
                )
        elif kind == "subterranean_passage":
            canvas.create_rectangle(
                x - s * 0.45,
                y - s * 0.28,
                x + s * 0.45,
                y + s * 0.28,
                fill=ink,
                outline=ink,
                stipple="gray50",
            )
        else:
            for i in range(5):
                yy = y - s * 0.3 + i * s * 0.15
                canvas.create_line(
                    x - s * 0.45, yy, x + s * 0.45, yy, fill=ink, width=w
                )
    elif kind in {"stalactite", "stalagmite"}:
        if kind == "stalactite":
            points = (
                x - s * 0.35,
                y - s * 0.35,
                x + s * 0.35,
                y - s * 0.35,
                x,
                y + s * 0.35,
            )
        else:
            points = (
                x - s * 0.35,
                y + s * 0.35,
                x + s * 0.35,
                y + s * 0.35,
                x,
                y - s * 0.35,
            )
        canvas.create_polygon(points, outline=ink, fill=floor, width=w)
    elif kind in {
        "rubble",
        "rubble_pile",
        "debris_field",
        "rockfall",
        "cave_in",
        "depression",
    }:
        if kind == "cave_in":
            canvas.create_rectangle(
                x - s * 0.42,
                y - s * 0.26,
                x + s * 0.42,
                y + s * 0.26,
                outline=ink,
                width=w,
            )
            canvas.create_line(
                x - s * 0.34,
                y - s * 0.18,
                x + s * 0.34,
                y + s * 0.18,
                fill=ink,
                width=w,
            )
            canvas.create_line(
                x + s * 0.34,
                y - s * 0.18,
                x - s * 0.34,
                y + s * 0.18,
                fill=ink,
                width=w,
            )
        count = 14 if kind in {"rubble_pile", "rockfall", "cave_in"} else 9
        for i in range(count):
            angle = i * math.tau / 9
            radius = s * (0.12 + 0.34 * ((i % 4) / 3))
            dot = s * (0.04 + 0.02 * (i % 2))
            canvas.create_oval(
                x + math.cos(angle) * radius - dot,
                y + math.sin(angle) * radius - dot,
                x + math.cos(angle) * radius + dot,
                y + math.sin(angle) * radius + dot,
                outline=ink,
                fill=ink if kind != "depression" else floor,
            )
    elif kind in {"crevasse", "cracked_ground", "sinkhole", "elevated_ledge", "natural_chimney"}:
        if kind == "sinkhole":
            for radius in (0.42, 0.27, 0.12):
                canvas.create_oval(
                    x - s * radius,
                    y - s * radius,
                    x + s * radius,
                    y + s * radius,
                    outline=ink,
                    width=w,
                )
        elif kind == "natural_chimney":
            for i in range(8):
                angle = i * math.tau / 8
                canvas.create_line(
                    x,
                    y,
                    x + math.cos(angle) * s * 0.42,
                    y + math.sin(angle) * s * 0.42,
                    fill=ink,
                    width=w,
                )
        elif kind == "elevated_ledge":
            canvas.create_line(
                x - s * 0.45,
                y - s * 0.1,
                x - s * 0.2,
                y + s * 0.25,
                x + s * 0.1,
                y + s * 0.1,
                x + s * 0.45,
                y + s * 0.3,
                fill=ink,
                width=w,
            )
            canvas.create_line(
                x - s * 0.45,
                y - s * 0.25,
                x + s * 0.45,
                y - s * 0.05,
                fill=ink,
                width=w,
            )
        elif kind in {"crevasse", "cracked_ground"}:
            canvas.create_line(
                x - s * 0.4,
                y - s * 0.4,
                x - s * 0.1,
                y - s * 0.1,
                x - s * 0.25,
                y + s * 0.2,
                x + s * 0.15,
                y,
                x + s * 0.4,
                y + s * 0.35,
                fill=ink,
                width=w,
            )
            if kind == "cracked_ground":
                canvas.create_line(
                    x - s * 0.05,
                    y - s * 0.08,
                    x - s * 0.28,
                    y + s * 0.22,
                    fill=ink,
                    width=w,
                )
                canvas.create_line(
                    x + s * 0.08,
                    y,
                    x + s * 0.32,
                    y - s * 0.24,
                    fill=ink,
                    width=w,
                )
    else:
        if draw_tk_vector_symbol(canvas, kind, x, y, s, ink, floor, w):
            return
        label = symbol_icon(kind).strip()[:2]
        canvas.create_oval(
            x - s * 0.42,
            y - s * 0.42,
            x + s * 0.42,
            y + s * 0.42,
            outline=ink,
            width=max(1, int(w * 0.8)),
        )
        canvas.create_text(
            x,
            y,
            text=label,
            fill=ink,
            font=("Arial", max(8, int(s * (0.62 if len(label) > 1 else 0.76))), "bold"),
        )


